// ── Theme persistence ────────────────────────────────────────

interface ThemeData {
  edgeColors?: Record<string, string>;
  edgeStatus?: Record<string, string>;
  edgeOpacity?: Record<string, number>;
  statusDot?: Record<string, string>;
  tierColors?: Record<string, string>;
}

function getThemeSnapshot(): ThemeData {
  return {
    edgeColors: { ...EDGE_COLORS },
    edgeStatus: { ...EDGE_STATUS },
    edgeOpacity: { ...EDGE_OPACITY },
    statusDot: { ...STATUS_DOT },
    tierColors: Object.fromEntries(Object.entries(TIER_COLORS)),
  };
}

function applyThemeData(t: ThemeData) {
  if (t.edgeColors) Object.assign(EDGE_COLORS, t.edgeColors);
  if (t.edgeStatus) Object.assign(EDGE_STATUS, t.edgeStatus);
  if (t.edgeOpacity) Object.assign(EDGE_OPACITY, t.edgeOpacity);
  if (t.statusDot) Object.assign(STATUS_DOT, t.statusDot);
  if (t.tierColors) {
    for (const [k, v] of Object.entries(t.tierColors)) TIER_COLORS[Number(k)] = v;
  }
}

async function loadTheme() {
  try {
    const res = await fetch('/api/theme');
    const data = await res.json();
    if (data && typeof data === 'object') applyThemeData(data);
  } catch {}
}

async function saveTheme() {
  try {
    await fetch('/api/theme', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(getThemeSnapshot()),
    });
  } catch {}
}

/** Rebuild SVG arrow markers after palette change */
function rebuildArrowMarkers() {
  if (!mainG) return;
  // Remove old markers
  mainG.selectAll('defs marker').remove();
  const defs = mainG.select('defs');
  if (defs.empty()) return;
  for (const [et, color] of Object.entries(EDGE_COLORS)) {
    defs.append('marker').attr('id', `arrow-${et}`)
      .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
      .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
      .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', color);
  }
  defs.append('marker').attr('id', 'arrow-broken')
    .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
    .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
    .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', EDGE_STATUS.broken);
  defs.append('marker').attr('id', 'arrow-deprecated')
    .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
    .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
    .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', EDGE_STATUS.deprecated);
  defs.append('marker').attr('id', 'arrow-active')
    .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
    .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
    .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', EDGE_STATUS.pulse);
}

/** Apply current palette to all rendered edges + nodes (no full re-render) */
function applyThemeLive() {
  rebuildArrowMarkers();
  if (!currentData || !mainG) return;
  const nodeMap = new Map(currentData.nodes.map(n => [n.id, n]));
  // Refresh edges
  currentData.edges.forEach((e, idx) => {
    const eG = mainG.select(`.edge-${idx}`);
    if (eG.empty()) return;
    eG.select('.edge-path')
      .attr('stroke', edgeStrokeColor(e))
      .attr('opacity', edgeOpacity(e))
      .attr('marker-end', edgeArrowUrl(e));
  });
  // Refresh node status dots, type borders, and tier dots
  for (const node of currentData.nodes) {
    const ng = mainG.select(`.node-${node.id}`);
    if (ng.empty()) continue;
    ng.select('.status-dot').attr('fill', statusColor(node));
    // Border = node type color
    const s = STYLE[node.type] || STYLE.config;
    const shape = ng.select('.shape-main');
    if (!node.deprecated && shape.node()) {
      shape.attr('stroke', s.stroke);
    }
    // Update tier dot colors
    const dotTiers = nodeTiersTouched.get(node.id);
    const sorted = dotTiers ? [...dotTiers].sort() : [node.tier];
    ng.selectAll('.tier-dot').each(function(this: SVGElement, _d: any, i: number) {
      const t = sorted[i];
      if (t != null) d3.select(this).attr('fill', TIER_COLORS[t] || TIER_COLOR_DEFAULT);
    });
  }
}

