// Map node type → subgroup + shape
function nodeGroup(type: string, id?: string): string {
  if (id === 'eng_cli_tools') return 'workers'; // CLI tools wrapper lives with its workers
  switch (type) {
    case 'trigger': return 'triggers';
    case 'script': return 'scripts';
    case 'engine': return 'engines';
    case 'store_db': case 'store_json': return 'stores';
    case 'service': return 'services';
    case 'config': return 'configs';
    case 'model': return 'models';
    case 'controller': return 'controllers';
    case 'daemon': return 'daemons';
    case 'bridge': return 'bridges';
    case 'worker': return 'workers';
    default: return 'stores';
  }
}

function nodeShape(type: string, id?: string): string {
  if (id === 'eng_cli_tools') return 'stadium'; // keep original shape
  switch (type) {
    case 'trigger': return 'parallelogram';
    case 'store_db': return 'cylinder';
    case 'controller': return 'hexagon';
    case 'daemon': return 'stadium';
    case 'bridge': return 'diamond';
    case 'worker': return 'hexagon';
    default: return 'rect';
  }
}

const TIER_LABELS: Record<number, string> = { 1: 'T1 React.', 2: 'T2 Adapt.', 3: 'T3 Delib.', 9: 'T9 N/A' };

function nodeSublabel(n: GraphNode): string {
  // Controllers: show level + status
  const lvl = n.level || (n.meta as any)?.level;
  const cs = n.controllerStatus || (n.meta as any)?.controllerStatus;
  if (n.type === 'controller' && lvl) {
    return `L${lvl}` + (cs ? ` · ${cs}` : '');
  }
  if (n.type === 'trigger') {
    // Show all cycles this hook participates in
    const tiers = nodeTiersTouched.get(n.id);
    if (tiers && tiers.size > 2) {
      return [...tiers].sort().map(t => `T${t}`).join(' + ');
    }
    if (tiers && tiers.size > 1) {
      return [...tiers].sort().map(t => TIER_LABELS[t] || `T${t}`).join(' + ');
    }
    return TIER_LABELS[n.tier] || n.meta.tier;
  }
  if (n.meta.path) {
    const parts = n.meta.path.split('/');
    return parts[parts.length - 1] || n.meta.path;
  }
  return n.meta.tier;
}

