// Simple fast hash for JSONL line dedup (FNV-1a inspired)
function lineHash(line: string): string {
  let h = 0x811c9dc5;
  for (let i = 0; i < line.length; i++) {
    h ^= line.charCodeAt(i);
    h = (h * 0x01000193) >>> 0;
  }
  return h.toString(36);
}

// ── Data-Driven Pulse Engine ────────────────────────────────
// All lookups built from graph data (nodes + edges). Zero hardcoded mappings.

// Resolved once from graph data in buildPulseMaps() — zero hardcoded IDs
let eventToNodeId: Map<string, string>;       // "SessionStart" → "evt_session_start"
let scriptBaseToNodeId: Map<string, string>;   // "hook-handler.cjs" → "scr_hook_handler"
let mcpPrefixToServiceId: Map<string, string>; // "ruvector" → "svc_rv_mcp"
let outgoingEdges: Map<string, string[]>;      // nodeId → ["nodeId→targetId", ...]
let incomingEdges: Map<string, string[]>;      // nodeId → ["sourceId→nodeId", ...]
let configuresTriggerId: Map<string, string>;  // triggerId → configNodeId (from 'configures' edges targeting triggers)
let configuresServiceId: Map<string, string>;  // serviceId → configNodeId (from 'configures' edges targeting services)
let userPromptNodeId: string | null;           // node ID for the user-prompt trigger (derived from logKeys)

function buildPulseMaps(nodes: GraphNode[], edges: GraphEdge[]) {
  eventToNodeId = new Map();
  scriptBaseToNodeId = new Map();
  mcpPrefixToServiceId = new Map();
  outgoingEdges = new Map();
  incomingEdges = new Map();
  configuresTriggerId = new Map();
  configuresServiceId = new Map();
  userPromptNodeId = null;

  const nodeById = new Map(nodes.map(n => [n.id, n]));

  for (const n of nodes) {
    const keys: string[] = (n as any).logKeys || [n.label];

    if (n.type === 'trigger') {
      for (const k of keys) eventToNodeId.set(k, n.id);
      // Detect the user-prompt trigger by checking logKeys for 'UserPromptSubmit'
      if (keys.includes('UserPromptSubmit')) userPromptNodeId = n.id;
    } else if (n.type === 'script' || n.type === 'engine') {
      for (const k of keys) scriptBaseToNodeId.set(k, n.id);
    } else if (n.type === 'service') {
      for (const k of keys) mcpPrefixToServiceId.set(k, n.id);
    }
  }

  // Build adjacency lists + derive config→target maps from 'configures' edges
  for (const e of edges) {
    const key = `${e.sourceId}→${e.targetId}:${e.type}`;
    const out = outgoingEdges.get(e.sourceId) || [];
    out.push(key);
    outgoingEdges.set(e.sourceId, out);
    const inc = incomingEdges.get(e.targetId) || [];
    inc.push(key);
    incomingEdges.set(e.targetId, inc);

    // Build configures maps: config→trigger and config→service
    if (e.type === 'configures') {
      const target = nodeById.get(e.targetId);
      if (target?.type === 'trigger') configuresTriggerId.set(e.targetId, e.sourceId);
      if (target?.type === 'service') configuresServiceId.set(e.targetId, e.sourceId);
    }
  }
}

// Resolve edge key: compound keys (with :type) match directly; old-format keys
// (sourceId→targetId) resolve to all matching compound keys so every edge pulses.
function resolveEdgeKeys(edgeKey: string): number[] {
  if (!edgeIndexMap) return [];
  // Direct match (compound key with :type suffix)
  const direct = edgeIndexMap.get(edgeKey);
  if (direct !== undefined) return [direct];
  // Fallback: find all compound keys matching this sourceId→targetId prefix
  const indices: number[] = [];
  for (const [k, idx] of edgeIndexMap) {
    if (k.startsWith(edgeKey + ':')) indices.push(idx);
  }
  return indices;
}

// Per-edge pulse color override (set by pulseEdgesByStatus, cleared on decay)
const edgePulseColor = new Map<number, string>();

// Pulse a single edge — no cascade (use pulseWithCascade for downstream propagation)
function pulseEdge(edgeKey: string, energy: number, color?: string) {
  if (!edgeIndexMap || energy < 0.05) return;
  const indices = resolveEdgeKeys(edgeKey);
  if (indices.length === 0) return;
  for (const idx of indices) {
    edgeEnergy.set(idx, Math.min(1.0, (edgeEnergy.get(idx) || 0) + energy));
    if (color) edgePulseColor.set(idx, color);
  }

  // Energize target node if it's a data store (read/write glow)
  const parts = edgeKey.split('→');
  const targetId = parts[1]?.split(':')[0]; // strip :type suffix if present
  if (targetId && currentData) {
    const tgt = currentData.nodes.find(n => n.id === targetId);
    if (tgt && PULSE_NODE_TYPES.has(tgt.type)) {
      nodeEnergy.set(targetId, Math.min(1.0, (nodeEnergy.get(targetId) || 0) + energy));
    }
  }
}

// Pulse an edge + cascade downstream with decay. Uses visited set to prevent loops.
const _cascadeVisited = new Set<string>();
export function pulseWithCascade(edgeKey: string, energy: number, _isRoot = true) {
  if (!edgeIndexMap || energy < 0.05) return;
  // Clear visited set at the start of each top-level call (button clicks, external triggers)
  // so edges can pulse again. processLines() also clears per batch.
  if (_isRoot) _cascadeVisited.clear();
  if (_cascadeVisited.has(edgeKey)) return;
  _cascadeVisited.add(edgeKey);
  pulseEdge(edgeKey, energy);
  const targetId = edgeKey.split('→')[1]?.split(':')[0]; // strip :type suffix if present
  const downstream = outgoingEdges.get(targetId);
  if (downstream) {
    for (const dk of downstream) pulseWithCascade(dk, energy * 0.3, false);
  }
}

/**
 * Pulse all edges matching a given status filter.
 * Used by the "pulse test" buttons in the toolbar.
 */
const STATUS_PULSE_COLORS: Record<string, string> = {
  active:  '#22D3EE',   // cyan
  idle:    '#A78BFA',   // purple
  broken:  '#EF4444',   // red
  pending: '#EF4444',   // red (same as broken)
};

export function pulseEdgesByStatus(status: string) {
  if (!currentData) return 0;
  const matching = currentData.edges.filter(e => {
    if (status === 'all') return true;
    const s = e.telemetry?.lastStatus || 'idle';
    if (status === 'broken') return s === 'broken' || s === 'pending';
    return s === status;
  });
  _cascadeVisited.clear();
  for (const e of matching) {
    const key = `${e.sourceId}→${e.targetId}`;
    const s = e.telemetry?.lastStatus || 'idle';
    // For 'all', use per-edge status color; otherwise use the batch color
    const color = status === 'all'
      ? (STATUS_PULSE_COLORS[s] || STATUS_PULSE_COLORS.idle)
      : (STATUS_PULSE_COLORS[status] || EDGE_STATUS.pulse);
    pulseEdge(key, 0.7, color);
  }
  return matching.length;
}

// Parse raw JSONL lines → pulse exact edges. Zero hardcoded node IDs.
function processLines(lines: string[]) {
  if (!edgeIndexMap || !eventToNodeId) return;
  // Reset cascade visited set per batch — each poll gets fresh cascade paths
  _cascadeVisited.clear();

  for (const raw of lines) {
    // V05: Skip already-processed lines to prevent re-pulsing on scope=all re-fetch
    const h = lineHash(raw);
    if (_processedLineHashes.has(h)) continue;
    _processedLineHashes.add(h);
    // Cap dedup set at 5000 entries to avoid unbounded memory growth
    if (_processedLineHashes.size > 5000) {
      const iter = _processedLineHashes.values();
      for (let i = 0; i < 1000; i++) { const v = iter.next().value; if (v) _processedLineHashes.delete(v); }
    }
    try {
      const obj = JSON.parse(raw);

      // ── Source 1: hook_progress → exact trigger→script edge + cascade ─
      if (obj.type === 'progress' && obj.data?.type === 'hook_progress') {
        const d = obj.data;
        const rawEvt = (d.hookName || d.hookEvent || '').split(':')[0]; // "PostToolUse:Edit" → "PostToolUse"
        const sourceId = eventToNodeId.get(rawEvt);
        const cmd: string = d.command || '';
        // Skip "callback" — Claude's built-in handler, not our scripts
        if (cmd === 'callback') continue;
        // Extract script basename from command path
        const cmdMatch = cmd.match(/helpers\/([a-zA-Z0-9._-]+)/);
        const targetId = cmdMatch ? scriptBaseToNodeId.get(cmdMatch[1]) : undefined;

        if (sourceId && targetId) {
          // Direct trigger→script + cascade downstream from script (0.3× per hop)
          pulseWithCascade(`${sourceId}→${targetId}`, 0.7);
        }
        // configures edges don't pulse — no events, always type color
        continue;
      }

      // ── Source 2: type=user + userType=external → UserPromptSubmit ─
      if (obj.type === 'user' && obj.userType === 'external' && userPromptNodeId) {
        const content = obj.message?.content;
        // Only count actual user text (not tool_result responses)
        const hasText = typeof content === 'string' ||
          (Array.isArray(content) && content.some((c: any) => c.type === 'text'));
        if (hasText) {
          // Pulse all outgoing edges from the user-prompt trigger + cascade
          const edges = outgoingEdges.get(userPromptNodeId);
          if (edges) {
            for (const ek of edges) pulseWithCascade(ek, 0.7);
          }
          // configures edges don't pulse — no events, always type color
        }
        continue;
      }

      // ── Learning Progress Events (P2.2) ──
      const lp = obj.type === 'learning_progress' ? obj
        : obj.data?.type === 'learning_progress' ? obj.data
        : null;
      if (lp) {
        const action: string = lp.action || '';
        const pulseNode = (id: string, e = 0.6) =>
          nodeEnergy.set(id, Math.min(1.0, (nodeEnergy.get(id) || 0) + e));

        switch (action) {
          case 'sona_trajectory':
            pulseNode('eng_sona_optimizer');
            pulseWithCascade('eng_learning_service→eng_sona_optimizer', 0.7);
            pulseWithCascade('eng_sona_optimizer→json_sona_patterns', 0.7);
            pulseWithCascade('eng_sona_optimizer→db_memory', 0.7);
            break;
          case 'ewc_consolidation':
            pulseNode('eng_ewc_consolidation');
            pulseWithCascade('eng_learning_service→eng_ewc_consolidation', 0.7);
            pulseWithCascade('eng_ewc_consolidation→json_ewc_fisher', 0.7);
            pulseWithCascade('eng_ewc_consolidation→db_memory', 0.7);
            break;
          case 'intelligence_consolidate':
            pulseNode('eng_intelligence');
            pulseWithCascade('eng_intelligence→json_intelligence_snapshot', 0.7);
            pulseWithCascade('eng_auto_memory→eng_intelligence', 0.7);
            break;
          case 'intelligence_feedback':
            pulseNode('eng_intelligence');
            // cfg_config_json→eng_intelligence is a configures edge — don't pulse
            break;
          case 'neural_pretrain':
            pulseNode('eng_cli_tools');
            pulseWithCascade('eng_learning_service→eng_sona_optimizer', 0.7);
            break;
          case 'pattern_store':
            pulseNode('db_memory');
            pulseWithCascade('eng_ewc_consolidation→db_memory', 0.7);
            break;
          case 'pattern_store_t2':
            pulseNode('db_patterns');
            pulseWithCascade('eng_hook_handler→db_patterns', 0.7);
            break;
          case 'cross_tier_bridge':
            pulseNode('eng_intelligence');
            pulseNode('db_patterns');
            pulseWithCascade('eng_intelligence→db_patterns', 0.8);
            pulseWithCascade('eng_intelligence→json_last_matched_patterns', 0.5);
            break;
          case 'trajectory_start':
            pulseNode('eng_hook_handler');
            pulseWithCascade('eng_hook_handler→json_current_trajectory', 0.6);
            break;
          case 'trajectory_end':
            pulseNode('eng_hook_handler');
            pulseNode('db_patterns');
            pulseWithCascade('eng_hook_handler→db_patterns', 0.7);
            pulseWithCascade('eng_hook_handler→json_current_trajectory', 0.5);
            break;
          case 'trajectory_step':
            pulseNode('eng_hook_handler');
            pulseWithCascade('eng_hook_handler→json_current_trajectory', 0.5);
            break;
        }
        continue;
      }

      // ── Source 3: tool_use → config→service + cascade from service ──
      if (obj.type === 'assistant' && obj.message?.content) {
        for (const b of obj.message.content) {
          if (b.type !== 'tool_use') continue;
          const name: string = b.name || '';
          if (!name.startsWith('mcp__')) continue;
          const server = name.split('__')[1]; // mcp__ruvector__brain_search → "ruvector"
          if (!server) continue;
          const svcId = mcpPrefixToServiceId.get(server);
          if (!svcId) continue;
          // configures edges don't pulse — no events, always type color
          // Service→downstream — cascade from service
          const svcEdges = outgoingEdges.get(svcId);
          if (svcEdges) {
            for (const ek of svcEdges) pulseWithCascade(ek, 0.5);
          }
        }
      }
    } catch {}
  }
}

// ── Geometry Helpers ────────────────────────────────────────

function nodePorts(n: GraphNode) {
  const hw = n.w / 2, hh = n.h / 2;
  const cylExt = n.shape === 'cylinder' ? 6 : 0;
  return {
    top:    { x: n.x!, y: n.y! - hh },
    bottom: { x: n.x!, y: n.y! + hh + cylExt },
    left:   { x: n.x! - hw, y: n.y! },
    right:  { x: n.x! + hw, y: n.y! },
  };
}

/**
 * Simple straight-line edge with center ports + small offset for parallel edges.
 */
function edgePath(src: GraphNode, tgt: GraphNode, offset = 0): { d: string; lx: number; ly: number } {
  const sp = nodePorts(src), tp = nodePorts(tgt);
  const dx = tgt.x! - src.x!, dy = tgt.y! - src.y!;
  let from: { x: number; y: number }, to: { x: number; y: number };
  let isVertical: boolean;
  if (Math.abs(dy) > 40) {
    isVertical = true;
    if (dy >= 0) { from = sp.bottom; to = tp.top; } else { from = sp.top; to = tp.bottom; }
  } else if (Math.abs(dx) > 20) {
    isVertical = false;
    if (dx >= 0) { from = sp.right; to = tp.left; } else { from = sp.left; to = tp.right; }
  } else {
    isVertical = true;
    from = sp.bottom; to = tp.top;
  }

  // Shift both endpoints to separate parallel/dual edges
  if (offset !== 0) {
    const spacing = 6;
    const shift = offset * spacing;
    if (isVertical) {
      from = { x: from.x + shift, y: from.y };
      to   = { x: to.x + shift,   y: to.y };
    } else {
      from = { x: from.x, y: from.y + shift };
      to   = { x: to.x,   y: to.y + shift };
    }
  }

  return { d: `M${from.x},${from.y} L${to.x},${to.y}`, lx: (from.x + to.x) / 2, ly: (from.y + to.y) / 2 - 4 };
}

/**
 * Single offset per edge. Groups by unordered visual pair so dual edges
 * (read+write between the same nodes) get separated.
 */
let _edgeOffsets: number[] = [];

function computeEdgeOffsets(edges: GraphEdge[]) {
  _edgeOffsets = new Array(edges.length).fill(0);
  if (!currentData) return;

  const visualSrc = (e: GraphEdge) => EDGE_REVERSE_VISUAL.has(e.type) ? e.targetId : e.sourceId;
  const visualTgt = (e: GraphEdge) => EDGE_REVERSE_VISUAL.has(e.type) ? e.sourceId : e.targetId;

  // Group by unordered visual pair — this catches dual edges (read+write same nodes)
  const pairs = new Map<string, number[]>();
  for (let i = 0; i < edges.length; i++) {
    const a = visualSrc(edges[i]), b = visualTgt(edges[i]);
    const k = a < b ? `${a}↔${b}` : `${b}↔${a}`;
    if (!pairs.has(k)) pairs.set(k, []);
    pairs.get(k)!.push(i);
  }
  for (const indices of pairs.values()) {
    if (indices.length <= 1) continue;
    for (let j = 0; j < indices.length; j++) {
      _edgeOffsets[indices[j]] = j - (indices.length - 1) / 2;
    }
  }
}

function groupBounds(nodes: GraphNode[], groupId: string): { x: number; y: number; w: number; h: number } | null {
  const members = nodes.filter(n => n.group === groupId && !detachedNodes.has(n.id));
  if (!members.length) return null;
  let x1 = Infinity, y1 = Infinity, x2 = -Infinity, y2 = -Infinity;
  for (const n of members) {
    x1 = Math.min(x1, n.x! - n.w / 2 - 16);
    y1 = Math.min(y1, n.y! - n.h / 2 - 16);
    x2 = Math.max(x2, n.x! + n.w / 2 + 16);
    y2 = Math.max(y2, n.y! + n.h / 2 + 16);
  }
  return { x: x1 - 10, y: y1 - 24, w: x2 - x1 + 20, h: y2 - y1 + 34 };
}

// ── Overlay Color ───────────────────────────────────────────

function getTierBorderColor(d: GraphNode): string {
  return TIER_COLORS[d.tier] || TIER_COLOR_DEFAULT;
}

// Keep for reference but no longer used for node borders
function getOverlayColor(d: GraphNode): string {
  if (!d.expected) return OVERLAY_COLORS.unexpected;
  if (!d.signals.exists) return OVERLAY_COLORS.missing;
  if (!d.signals.healthy || !d.signals.active) return OVERLAY_COLORS.degraded;
  return OVERLAY_COLORS.found;
}

function statusColor(d: GraphNode): string {
  // Deprecated: intentionally removed — dim grey
  if (d.deprecated) return STATUS_DOT.deprecated;
  // Phantom: not installed / optional — grey (not red)
  if (d.meta?.phantom && !d.signals.exists) return STATUS_DOT.phantom;
  // Dormant: configured but not scheduled — blue/idle (not red)
  if (d.meta?.dormant && !d.signals.exists) return STATUS_DOT.idle;
  // Actually missing: should exist but doesn't — red
  if (!d.signals.exists) return STATUS_DOT.missing;
  // Exists but unhealthy — yellow
  if (!d.signals.healthy) return STATUS_DOT.unhealthy;
  // Active — green
  if (d.signals.active) return STATUS_DOT.active;
  // Idle — blue
  return STATUS_DOT.idle;
}

// ── Tooltip ─────────────────────────────────────────────────

function showTooltip(event: MouseEvent, html: string) {
  tooltip.innerHTML = html;
  tooltip.style.display = 'block';
  tooltip.style.left = event.pageX + 12 + 'px';
  tooltip.style.top = event.pageY + 12 + 'px';
}

function hideTooltip() { tooltip.style.display = 'none'; }

function nodeStatusInfo(d: { signals: { exists: boolean; healthy: boolean; active: boolean }; deprecated?: boolean; meta?: { phantom?: boolean; dormant?: boolean }; onDemand?: boolean }): { status: string; hint: string; color: string } {
  if (d.deprecated) return { status: 'DEPRECATED', hint: 'Intentionally removed from the system', color: STATUS_DOT.deprecated };
  if (d.meta?.phantom && !d.signals.exists) return { status: 'PHANTOM', hint: 'Optional — not installed in this configuration', color: STATUS_DOT.phantom };
  if (d.meta?.dormant && !d.signals.exists) return { status: 'DORMANT', hint: 'Configured but not scheduled by the daemon', color: STATUS_DOT.idle };
  if (!d.signals.exists) return { status: 'MISSING', hint: 'Should exist but file not found', color: STATUS_DOT.missing };
  if (!d.signals.healthy) return { status: 'DEGRADED', hint: 'Exists but not fully healthy', color: STATUS_DOT.unhealthy };
  if (d.signals.active) return { status: 'ACTIVE', hint: 'Running and recently used', color: STATUS_DOT.active };
  return { status: 'IDLE', hint: 'Ready, waiting to be used', color: STATUS_DOT.idle };
}

function nodeTooltipHtml(d: GraphNode): string {
  const s = d.signals;
  const info = nodeStatusInfo(d);
  const isAbsent = d.deprecated || (d.meta?.phantom && !s.exists) || (d.meta?.dormant && !s.exists);
  const sig = (ok: boolean, label: string) => isAbsent
    ? `<span style="color:${info.color}">—</span> ${label}`
    : ok ? `<span style="color:${STATUS_DOT.active}">&#10003;</span> ${label}` : `<span style="color:${STATUS_DOT.missing}">&#10007;</span> ${label}`;
  return `
    <div style="font-weight:600;margin-bottom:4px;color:${STYLE[d.type]?.stroke || '#fff'}">${d.label}</div>
    <div>Type: <b>${d.type}</b> &middot; Tier: <b>${d.meta.tier}</b></div>
    <div style="margin:4px 0">${sig(s.exists, 'exists')} &middot; ${sig(s.healthy, 'healthy')} &middot; ${sig(s.active, 'active')} &rarr; <span style="color:${info.color};font-weight:600">${info.status}</span></div>
    <div style="color:${info.color};font-size:10px;margin-top:2px">${info.hint}</div>
    ${d.meta.path ? `<div style="margin-top:4px;color:#94a3b8">${d.meta.path}</div>` : ''}
    ${d.meta.description ? `<div style="margin-top:4px;color:#cbd5e1;font-style:italic">${d.meta.description}</div>` : ''}
    ${d.meta.rowCount !== undefined && (d.type === 'store_db' || d.type === 'store_json') ? `<div>${(d.meta.countLabel || 'Rows').charAt(0).toUpperCase() + (d.meta.countLabel || 'rows').slice(1)}: ${d.meta.rowCount}</div>` : ''}
    ${d.meta.rowCount !== undefined && d.type === 'worker' ? `<div>Runs: ${d.meta.rowCount}</div>` : ''}
    ${d.meta.fileSize ? `<div>Size: ${(d.meta.fileSize/1024).toFixed(1)} KB</div>` : ''}
    ${d.meta.archTier ? `<div style="margin-top:4px;color:${STATUS_DOT.onDemand}">&#9638; ${d.meta.archTier}</div>` : ''}
    ${d.meta.statusNote ? `<div style="margin-top:4px;color:${STATUS_DOT.unhealthy};max-width:360px;line-height:1.3">&#9888; ${d.meta.statusNote}</div>` : ''}
    ${(d.bugRefs?.length || (d.meta as any)?.bugRefs?.length) ? `<div style="color:#fca5a5;margin-top:4px">&#9888; Bugs: ${(d.bugRefs || (d.meta as any)?.bugRefs || []).join(', ')}</div>` : ''}
    ${!d.expected ? '<div style="color:#06b6d4;margin-top:4px">&#9888; Unexpected</div>' : ''}`;
}

// ── Layout ──────────────────────────────────────────────────

function layoutNodes(nodes: GraphNode[]): void {
  // Separate expected and unexpected nodes
  const expectedNodes = nodes.filter(n => n.expected);
  const unexpectedNodes = nodes.filter(n => !n.expected);

  // Layout expected nodes by layer
  const byLayer: Record<number, GraphNode[]> = {};
  for (const n of expectedNodes) {
    const layer = n.layer ?? 3;
    if (!byLayer[layer]) byLayer[layer] = [];
    byLayer[layer].push(n);
  }

  for (const [layer, layerNodes] of Object.entries(byLayer)) {
    const y = LAYER_Y[Number(layer)] || 700;
    layerNodes.sort((a, b) => (a.tier - b.tier) || a.type.localeCompare(b.type));
    const spacing = Math.max(NODE_W + 20, 170);
    const startX = -(layerNodes.length - 1) * spacing / 2;

    layerNodes.forEach((n, i) => {
      const saved = savedPositions[n.id];
      if (saved) {
        n.x = saved.x;
        n.y = saved.y;
      } else {
        n.x = startX + i * spacing;
        n.y = y;
      }
    });
  }

  // Layout unexpected nodes below all expected layers (bottom + 100px)
  if (unexpectedNodes.length > 0) {
    const maxExpectedY = Math.max(...Object.values(LAYER_Y), 700);
    const unexpectedY = maxExpectedY + 100;
    unexpectedNodes.sort((a, b) => (a.tier - b.tier) || a.type.localeCompare(b.type));
    const spacing = Math.max(NODE_W + 20, 170);
    const startX = -(unexpectedNodes.length - 1) * spacing / 2;

    unexpectedNodes.forEach((n, i) => {
      const saved = savedPositions[n.id];
      if (saved) {
        n.x = saved.x;
        n.y = saved.y;
      } else {
        n.x = startX + i * spacing;
        n.y = unexpectedY;
      }
    });
  }
}

// ── Enrich Nodes ────────────────────────────────────────────

function enrichNode(n: GraphNode): GraphNode {
  n.w = NODE_W;
  n.h = NODE_H;
  n.shape = nodeShape(n.type, n.id);
  n.group = n.expected ? nodeGroup(n.type, n.id) : 'utilities';
  n.sublabel = nodeSublabel(n);
  return n;
}

// ── Draw Subgraphs ──────────────────────────────────────────

function drawSubgraphs(g: any, nodes: GraphNode[], edges: GraphEdge[], nodeMap: Map<string, GraphNode>) {
  for (const sg of SUBGRAPHS) {
    const bounds = groupBounds(nodes, sg.id);
    if (!bounds) continue;
    const sgG = g.append('g').attr('class', `sg-${sg.id}`).attr('cursor', 'grab');
    sgG.append('rect').attr('class', 'sg-bg')
      .attr('x', bounds.x).attr('y', bounds.y)
      .attr('width', bounds.w).attr('height', bounds.h)
      .attr('rx', 10).attr('fill', sg.color).attr('stroke', sg.borderColor)
      .attr('stroke-width', 2).attr('opacity', showBoxes ? 0.3 : 0);
    sgG.append('text').attr('class', 'sg-label')
      .attr('x', bounds.x + 8).attr('y', bounds.y + 14)
      .attr('fill', sg.borderColor).attr('font-size', 11).attr('font-weight', 'bold')
      .attr('opacity', showBoxes ? 1 : 0)
      .text(sg.label);

    // Group drag — moves all attached members together
    let dragStartX = 0, dragStartY = 0;
    const startPositions: { node: GraphNode; sx: number; sy: number }[] = [];

    const drag = d3.drag()
      .on('start', function(this: SVGGElement, ev: any) {
        sgG.attr('cursor', 'grabbing');
        dragStartX = ev.x; dragStartY = ev.y;
        startPositions.length = 0;
        const members = nodes.filter(n => n.group === sg.id && !detachedNodes.has(n.id));
        for (const m of members) startPositions.push({ node: m, sx: m.x!, sy: m.y! });
      })
      .on('drag', function(this: SVGGElement, ev: any) {
        const dx = ev.x - dragStartX, dy = ev.y - dragStartY;
        for (const { node, sx, sy } of startPositions) {
          node.x = sx + dx; node.y = sy + dy;
          g.select(`.node-${node.id}`).attr('transform', `translate(${node.x},${node.y})`);
        }
        refreshSubgraphs(g, nodes, edges, nodeMap);
        refreshEdges(g, edges, nodeMap);
      })
      .on('end', function() { sgG.attr('cursor', 'grab'); markDirty(); });

    sgG.call(drag);
  }
}

const SPLIT_DIST = 160;
const MERGE_DIST = 120;

// Distance from a node's bounding box edge to a cluster's bounding box edge
function distToCluster(node: GraphNode, members: GraphNode[]): number {
  if (members.length === 0) return Infinity;
  let x1 = Infinity, y1 = Infinity, x2 = -Infinity, y2 = -Infinity;
  for (const s of members) {
    x1 = Math.min(x1, s.x! - s.w / 2); y1 = Math.min(y1, s.y! - s.h / 2);
    x2 = Math.max(x2, s.x! + s.w / 2); y2 = Math.max(y2, s.y! + s.h / 2);
  }
  // Distance from node bbox edge to cluster bbox edge (0 if overlapping)
  const nL = node.x! - node.w / 2, nR = node.x! + node.w / 2;
  const nT = node.y! - node.h / 2, nB = node.y! + node.h / 2;
  const dx = Math.max(x1 - nR, 0, nL - x2);
  const dy = Math.max(y1 - nB, 0, nT - y2);
  return Math.hypot(dx, dy);
}

function updateDetach(node: GraphNode, allNodes: GraphNode[]) {
  const sameGroup = allNodes.filter(n => n.group === node.group && n.id !== node.id);
  const mainMembers = sameGroup.filter(n => !detachedNodes.has(n.id));

  // Distance to main parent group
  const distToMain = distToCluster(node, mainMembers);

  if (!detachedNodes.has(node.id)) {
    // Currently attached to main — only split based on distance to main
    if (distToMain > SPLIT_DIST) detachedNodes.add(node.id);
  } else {
    // Currently detached — only merge back to MAIN if close to main
    if (distToMain < MERGE_DIST) {
      detachedNodes.delete(node.id);
    } else {
      // Check if in a satellite and drifted away from it
      for (const [sid, sat] of satelliteGroups) {
        if (sat.parentGroup !== node.group || !sat.members.has(node.id)) continue;
        const satSiblings = sameGroup.filter(n => sat.members.has(n.id) && n.id !== node.id);
        if (distToCluster(node, satSiblings) > SPLIT_DIST) {
          sat.members.delete(node.id);
          if (sat.members.size < 2) satelliteGroups.delete(sid);
        }
        break;
      }
    }
  }

  // Rebuild satellite clusters from all detached nodes in this group
  rebuildSatellites(node.group, allNodes);
}

function rebuildSatellites(parentGroup: string, allNodes: GraphNode[]) {
  // Remove old satellites for this parent group
  for (const [sid, sat] of satelliteGroups) {
    if (sat.parentGroup === parentGroup) satelliteGroups.delete(sid);
  }

  // Get all detached nodes from this group
  const detached = allNodes.filter(n => n.group === parentGroup && detachedNodes.has(n.id));
  if (!detached.length) return;

  // Single-linkage clustering using bbox-to-bbox distance with MERGE_DIST threshold
  // (same distance as merge-back, so nodes that "look like they belong together" cluster)
  const assigned = new Set<string>();
  for (const node of detached) {
    if (assigned.has(node.id)) continue;
    const cluster: GraphNode[] = [node];
    assigned.add(node.id);

    // BFS — check distance from node bbox to cluster bbox (not point-to-point)
    let i = 0;
    while (i < cluster.length) {
      const current = cluster[i++];
      for (const other of detached) {
        if (assigned.has(other.id)) continue;
        // Check distance to the entire cluster so far, not just `current`
        if (distToCluster(other, cluster) < MERGE_DIST) {
          cluster.push(other);
          assigned.add(other.id);
        }
      }
    }

    const sid = `sat_${parentGroup}_${++satelliteCounter}`;
    satelliteGroups.set(sid, { parentGroup, members: new Set(cluster.map(n => n.id)) });
  }
}

function satelliteBounds(nodes: GraphNode[], memberIds: Set<string>): { x: number; y: number; w: number; h: number } | null {
  const members = nodes.filter(n => memberIds.has(n.id));
  if (!members.length) return null;
  let x1 = Infinity, y1 = Infinity, x2 = -Infinity, y2 = -Infinity;
  for (const n of members) {
    x1 = Math.min(x1, n.x! - n.w / 2 - 12);
    y1 = Math.min(y1, n.y! - n.h / 2 - 12);
    x2 = Math.max(x2, n.x! + n.w / 2 + 12);
    y2 = Math.max(y2, n.y! + n.h / 2 + 12);
  }
  return { x: x1 - 6, y: y1 - 20, w: x2 - x1 + 12, h: y2 - y1 + 26 };
}

// Track which satellite SVGs exist and their current member snapshot
const liveSatelliteSvgs = new Map<string, string>(); // sid → serialized member set

function refreshSubgraphs(g: any, nodes: GraphNode[], edges?: GraphEdge[], nodeMap?: Map<string, GraphNode>) {
  // Update main subgraph boxes
  for (const sg of SUBGRAPHS) {
    const bounds = groupBounds(nodes, sg.id);
    const sgG = g.select(`.sg-${sg.id}`);
    if (!bounds) { sgG.select('.sg-bg').attr('opacity', 0); sgG.select('.sg-label').attr('opacity', 0); continue; }
    sgG.select('.sg-bg').attr('x', bounds.x).attr('y', bounds.y).attr('width', bounds.w).attr('height', bounds.h)
      .attr('opacity', showBoxes ? 0.3 : 0);
    sgG.select('.sg-label').attr('x', bounds.x + 8).attr('y', bounds.y + 14).attr('opacity', showBoxes ? 1 : 0);
  }

  if (!showBoxes) {
    g.selectAll('.satellite-group').remove();
    liveSatelliteSvgs.clear();
    return;
  }

  // Remove satellites that no longer exist
  const activeSids = new Set(satelliteGroups.keys());
  for (const sid of liveSatelliteSvgs.keys()) {
    if (!activeSids.has(sid)) {
      g.select(`.sat-${sid}`).remove();
      liveSatelliteSvgs.delete(sid);
    }
  }

  // Create or update satellite groups
  for (const [sid, sat] of satelliteGroups) {
    const parentSg = SUBGRAPHS.find(s => s.id === sat.parentGroup);
    if (!parentSg) continue;
    const bounds = satelliteBounds(nodes, sat.members);
    if (!bounds) continue;

    const memberKey = [...sat.members].sort().join(',');
    let satG = g.select(`.sat-${sid}`);

    if (satG.empty() || liveSatelliteSvgs.get(sid) !== memberKey) {
      // Create new satellite SVG (or recreate if members changed)
      if (!satG.empty()) satG.remove();

      // Insert before layer groups so satellites render behind edges/nodes
      const insertBefore = edgeLayer?.node() || null;
      const parent = insertBefore ? insertBefore.parentNode : g.node();
      const newG = document.createElementNS('http://www.w3.org/2000/svg', 'g');
      if (insertBefore) parent.insertBefore(newG, insertBefore);
      else parent.appendChild(newG);
      satG = d3.select(newG)
        .attr('class', `satellite-group sat-${sid}`)
        .attr('cursor', 'grab');

      satG.append('rect').attr('class', 'sat-bg')
        .attr('x', bounds.x).attr('y', bounds.y)
        .attr('width', bounds.w).attr('height', bounds.h)
        .attr('rx', 8)
        .attr('fill', parentSg.color)
        .attr('stroke', parentSg.borderColor)
        .attr('stroke-width', 1.5)
        .attr('stroke-dasharray', '6,3')
        .attr('opacity', 0.3);

      satG.append('text').attr('class', 'sat-label')
        .attr('x', bounds.x + 6).attr('y', bounds.y + 12)
        .attr('fill', parentSg.borderColor).attr('font-size', 9).attr('font-style', 'italic')
        .attr('opacity', 0.8)
        .text(`${parentSg.label} (${sat.members.size})`);

      // Drag handler for satellite — moves all member nodes
      let dragStartX = 0, dragStartY = 0;
      const startPositions: { node: GraphNode; sx: number; sy: number }[] = [];

      const satDrag = d3.drag()
        .on('start', function(this: SVGGElement, ev: any) {
          satG.attr('cursor', 'grabbing');
          dragStartX = ev.x; dragStartY = ev.y;
          startPositions.length = 0;
          for (const nid of sat.members) {
            const n = nodes.find(nd => nd.id === nid);
            if (n) startPositions.push({ node: n, sx: n.x!, sy: n.y! });
          }
        })
        .on('drag', function(this: SVGGElement, ev: any) {
          const dx = ev.x - dragStartX, dy = ev.y - dragStartY;
          for (const { node, sx, sy } of startPositions) {
            node.x = sx + dx; node.y = sy + dy;
            g.select(`.node-${node.id}`).attr('transform', `translate(${node.x},${node.y})`);
          }
          // Update only the satellite rect + label position (not rebuild)
          const b = satelliteBounds(nodes, sat.members);
          if (b) {
            satG.select('.sat-bg').attr('x', b.x).attr('y', b.y).attr('width', b.w).attr('height', b.h);
            satG.select('.sat-label').attr('x', b.x + 6).attr('y', b.y + 12);
          }
          // Update edges
          if (edges && nodeMap) refreshEdges(g, edges, nodeMap);
        })
        .on('end', function() { satG.attr('cursor', 'grab'); markDirty(); });

      satG.call(satDrag);
      liveSatelliteSvgs.set(sid, memberKey);
    } else {
      // Just update position of existing satellite rect
      satG.select('.sat-bg').attr('x', bounds.x).attr('y', bounds.y).attr('width', bounds.w).attr('height', bounds.h);
      satG.select('.sat-label').attr('x', bounds.x + 6).attr('y', bounds.y + 12)
        .text(`${parentSg.label} (${sat.members.size})`);
    }
  }
}

// ── Edge Color/Opacity helpers (single source — used by draw, refresh, decay, hover) ──

function edgeStrokeColor(e: GraphEdge): string {
  if (e.deprecated) return EDGE_STATUS.deprecated;
  if (e.telemetry?.lastStatus === 'broken') return EDGE_STATUS.broken;
  if (e.bugRefs?.length) return '#ff6b6b'; // coral red for bug-severed edges
  return EDGE_COLORS[e.type] || EDGE_COLOR_DEFAULT;
}

// Group opacity multipliers for edge visibility control
let EDGE_GROUP_OPACITY: Record<string, number> = {
  workers: 0.3,      // CLI Tools edges (dimmed by default — many edges, on-demand)
  controllers: 0.5,  // ADR-053 controller edges (dimmed — internal wiring)
};

function edgeGroupKey(e: GraphEdge): string | null {
  if (e.sourceId?.startsWith('wrk_') || e.targetId?.startsWith('wrk_') || e.sourceId === 'eng_cli_tools') return 'workers';
  if (e.sourceId?.startsWith('ctrl_') || e.targetId?.startsWith('ctrl_')) return 'controllers';
  return null;
}

function edgeOpacity(e: GraphEdge): number {
  if (e.deprecated) return EDGE_OPACITY.deprecated;
  const s = e.telemetry?.lastStatus || 'idle';
  let base: number;
  if (s === 'broken') base = EDGE_OPACITY.broken;
  else if (s === 'active') base = EDGE_OPACITY.active;
  else base = EDGE_OPACITY.idle;
  // Apply group multiplier
  const gk = edgeGroupKey(e);
  if (gk && EDGE_GROUP_OPACITY[gk] !== undefined) base *= EDGE_GROUP_OPACITY[gk];
  return Math.max(0.03, base);
}

function edgeArrowUrl(e: GraphEdge): string {
  if (e.deprecated) return 'url(#arrow-deprecated)';
  if (e.telemetry?.lastStatus === 'broken') return 'url(#arrow-broken)';
  return `url(#arrow-${e.type})`;
}

// ── Draw Edges ──────────────────────────────────────────────

function drawEdges(g: any, edges: GraphEdge[], nodeMap: Map<string, GraphNode>) {
  computeEdgeOffsets(edges);
  edgeIndexMap = new Map();
  edges.forEach((e, idx) => {
    const src = nodeMap.get(e.sourceId), tgt = nodeMap.get(e.targetId);
    if (!src || !tgt) return;
    edgeIndexMap!.set(`${e.sourceId}→${e.targetId}:${e.type}`, idx);
    // Reverse visual flow for reads/uses — data flows target→source
    const reversed = EDGE_REVERSE_VISUAL.has(e.type);
    const route = edgePath(reversed ? tgt : src, reversed ? src : tgt, _edgeOffsets[idx]);
    const eG = g.append('g').attr('class', `edge-g edge-${idx}`);
    // Invisible wide hit area for hover
    eG.append('path').attr('class', 'edge-hit')
      .attr('d', route.d).attr('fill', 'none')
      .attr('stroke', 'transparent').attr('stroke-width', 12)
      .style('cursor', 'help');
    const eStroke = edgeStrokeColor(e);
    const eOpacity = edgeOpacity(e);
    eG.append('path').attr('class', 'edge-path')
      .attr('d', route.d).attr('fill', 'none')
      .attr('stroke', eStroke).attr('stroke-width', e.deprecated ? 1 : 1.5)
      .attr('opacity', eOpacity).style('pointer-events', 'none')
      .attr('marker-end', edgeArrowUrl(e))
      .attr('stroke-dasharray', e.deprecated ? '4,4' : null);
    if (e.label) {
      eG.append('text').attr('class', 'edge-label')
        .attr('x', route.lx).attr('y', route.ly)
        .attr('text-anchor', 'middle')
        .attr('fill', e.deprecated ? STATUS_DOT.deprecated : '#555').attr('font-size', 8)
        .text(e.label.length > 24 ? e.label.slice(0, 22) + '..' : e.label);
    }
    // Edge tooltip
    const hitPath = eG.select('.edge-hit');
    hitPath.on('mouseenter', (event: MouseEvent) => {
      const typeColor = EDGE_COLORS[e.type] || EDGE_COLOR_DEFAULT;
      eG.select('.edge-path').attr('stroke-width', 3).attr('opacity', 0.9);
      const tooltipStatusColors: Record<string, string> = { active: STATUS_DOT.active, idle: '#94a3b8', broken: EDGE_STATUS.broken };
      const statusLabel = e.telemetry.lastStatus || 'unknown';
      const sColor = tooltipStatusColors[statusLabel] || '#94a3b8';
      const html = `
        <div style="font-weight:600;color:${typeColor}">${e.type.toUpperCase()}</div>
        <div>${src.label} &rarr; ${tgt.label}</div>
        ${e.label ? `<div style="color:#94a3b8">${e.label}</div>` : ''}
        <div style="margin-top:4px">Fired: <b>${e.telemetry.countThisSession ?? 0}</b>x this session</div>
        ${e.telemetry.lastFired ? `<div>Last: ${new Date(e.telemetry.lastFired).toLocaleTimeString()}</div>` : ''}
        <div>Status: <b style="color:${sColor}">${statusLabel.toUpperCase()}</b></div>`;
      showTooltip(event, html);
    }).on('mousemove', (event: MouseEvent) => {
      tooltip.style.left = event.pageX + 12 + 'px';
      tooltip.style.top = event.pageY + 12 + 'px';
    }).on('mouseleave', () => {
      eG.select('.edge-path').attr('stroke-width', e.deprecated ? 1 : 1.5).attr('opacity', edgeOpacity(e));
      hideTooltip();
    });
  });
}

function refreshEdges(g: any, edges: GraphEdge[], nodeMap: Map<string, GraphNode>) {
  edges.forEach((e, idx) => {
    const src = nodeMap.get(e.sourceId), tgt = nodeMap.get(e.targetId);
    if (!src || !tgt) return;
    const reversed = EDGE_REVERSE_VISUAL.has(e.type);
    const route = edgePath(reversed ? tgt : src, reversed ? src : tgt, _edgeOffsets[idx]);
    const eG = g.select(`.edge-${idx}`);
    eG.select('.edge-hit').attr('d', route.d);
    const strokeColor = edgeStrokeColor(e);
    const opacity = edgeOpacity(e);
    eG.select('.edge-path').attr('d', route.d)
      .attr('stroke', strokeColor).attr('opacity', opacity).attr('marker-end', edgeArrowUrl(e));
    const txt = eG.select('text');
    if (!txt.empty()) txt.attr('x', route.lx).attr('y', route.ly);
  });
}

// ── Draw Nodes ──────────────────────────────────────────────

function drawNodes(g: any, nodes: GraphNode[], edges: GraphEdge[], nodeMap: Map<string, GraphNode>) {
  for (const node of nodes) {
    const style = STYLE[node.type] || STYLE.config;
    // Border color = node type (not tier) — tier info shown via dots
    const borderColor = style.stroke;
    const borderWidth = 2;
    const hw = node.w / 2, hh = node.h / 2;

    const ng = g.append('g')
      .attr('class', `node-${node.id} node-group`)
      .attr('transform', `translate(${node.x},${node.y})`)
      .attr('cursor', 'pointer')
      .style('filter', 'drop-shadow(0 2px 4px rgba(0,0,0,0.5))')
      .datum(node);

    // Shape — border color = tier/cycle (gradient if multi-tier)
    if (node.shape === 'cylinder') {
      const ry = 6;
      ng.append('rect').attr('class', 'shape-main')
        .attr('x', -hw).attr('y', -hh + ry).attr('width', node.w).attr('height', node.h - ry)
        .attr('rx', 4).attr('fill', style.fill).attr('stroke', borderColor).attr('stroke-width', borderWidth);
      ng.append('ellipse').attr('cx', 0).attr('cy', -hh + ry)
        .attr('rx', hw).attr('ry', ry)
        .attr('fill', style.fill).attr('stroke', borderColor).attr('stroke-width', borderWidth);
      ng.append('ellipse').attr('cx', 0).attr('cy', hh)
        .attr('rx', hw).attr('ry', ry)
        .attr('fill', style.fill).attr('stroke', borderColor).attr('stroke-width', borderWidth);
    } else if (node.shape === 'parallelogram') {
      const sk = 15;
      ng.append('polygon').attr('class', 'shape-main')
        .attr('points', `${-hw + sk},${-hh} ${hw + sk},${-hh} ${hw - sk},${hh} ${-hw - sk},${hh}`)
        .attr('fill', style.fill).attr('stroke', borderColor).attr('stroke-width', borderWidth);
    } else if (node.shape === 'hexagon') {
      const sx = hw * 0.25;
      ng.append('polygon').attr('class', 'shape-main')
        .attr('points', `${-hw + sx},${-hh} ${hw - sx},${-hh} ${hw},0 ${hw - sx},${hh} ${-hw + sx},${hh} ${-hw},0`)
        .attr('fill', style.fill).attr('stroke', borderColor).attr('stroke-width', borderWidth);
    } else if (node.shape === 'stadium') {
      // Pill/stadium shape — rounded ends for daemons (long-running processes)
      ng.append('rect').attr('class', 'shape-main')
        .attr('x', -hw).attr('y', -hh).attr('width', node.w).attr('height', node.h)
        .attr('rx', hh).attr('ry', hh)  // fully rounded ends
        .attr('fill', style.fill).attr('stroke', borderColor).attr('stroke-width', borderWidth);
    } else if (node.shape === 'diamond') {
      // Diamond shape — bridge layer connector
      ng.append('polygon').attr('class', 'shape-main')
        .attr('points', `0,${-hh} ${hw},0 0,${hh} ${-hw},0`)
        .attr('fill', style.fill).attr('stroke', borderColor).attr('stroke-width', borderWidth);
    } else {
      ng.append('rect').attr('class', 'shape-main')
        .attr('x', -hw).attr('y', -hh).attr('width', node.w).attr('height', node.h)
        .attr('rx', 6).attr('fill', style.fill).attr('stroke', borderColor).attr('stroke-width', borderWidth);
    }

    // Conceptual nodes: dashed border, slightly dimmed — no physical file, design concept only
    if ((node as any).conceptual || node.meta?.conceptual) {
      ng.selectAll('.shape-main, rect, polygon, ellipse')
        .attr('stroke-dasharray', '4,4');
      ng.style('opacity', '0.7');
    }

    // Deprecated nodes: gray stroke, dashed border, dimmed — node stays but is visually de-emphasized
    if (node.deprecated) {
      ng.selectAll('.shape-main, rect, polygon, ellipse')
        .attr('stroke', TIER_COLOR_DEFAULT).attr('stroke-dasharray', '6,3').attr('opacity', 0.25);
      ng.selectAll('text').attr('fill', TIER_COLOR_DEFAULT);
      ng.style('opacity', '0.3');
    }
    // Dashed border for missing nodes (non-deprecated)
    else if (node.expected && !node.signals.exists) {
      if (node.meta?.phantom) {
        // Phantom: dashed stroke + very dim — file never existed in TF02
        ng.selectAll('.shape-main, rect, polygon, ellipse')
          .attr('stroke-dasharray', '4,4').attr('opacity', 0.3);
      } else if (node.onDemand) {
        // On-demand: dotted + dimmer (expected to not exist until runtime)
        ng.select('.shape-main, rect, polygon, ellipse')
          .attr('stroke-dasharray', '2,4').attr('opacity', 0.5);
      } else {
        ng.select('.shape-main, rect, polygon, ellipse').attr('stroke-dasharray', '5,3');
      }
    }

    // Tier dots (bottom-left) — shown on ALL nodes, colored per tier
    const dotTiers = nodeTiersTouched.get(node.id);
    const sortedTiers = dotTiers ? [...dotTiers].sort() : [node.tier];
    {
      const badgeX = -hw + 6;
      const badgeY = hh - 6;
      sortedTiers.forEach((t, i) => {
        ng.append('circle').attr('class', 'tier-dot')
          .attr('cx', badgeX + i * 10).attr('cy', badgeY).attr('r', 3.5)
          .attr('fill', TIER_COLORS[t] || TIER_COLOR_DEFAULT).attr('stroke', '#111').attr('stroke-width', 0.8);
      });
      ng.append('title').text(`Tier: ${sortedTiers.map(t => `T${t}`).join(', ')}`);
    }

    // Labels
    ng.append('text').attr('text-anchor', 'middle')
      .attr('y', node.sublabel ? -4 : 4)
      .attr('fill', style.text).attr('font-size', 11).attr('font-weight', 'bold')
      .text(node.label.length > 18 ? node.label.slice(0, 16) + '..' : node.label);
    if (node.sublabel) {
      ng.append('text').attr('text-anchor', 'middle').attr('y', 10)
        .attr('fill', style.text).attr('font-size', 9).attr('opacity', 0.7)
        .text(node.sublabel.length > 22 ? node.sublabel.slice(0, 20) + '..' : node.sublabel);
    }

    // Status dot
    const dotColor = statusColor(node);
    const dotG = ng.append('g').style('cursor', 'help');
    dotG.append('circle').attr('class', 'status-dot')
      .attr('cx', hw - 8).attr('cy', -hh + 8).attr('r', 7)
      .attr('fill', dotColor).attr('stroke', '#222').attr('stroke-width', 1.5);
    dotG.append('title').text(`${node.label}: ${node.signals.exists ? 'exists' : 'missing'}, ${node.signals.active ? 'active' : 'idle'}${node.meta.statusNote ? ' — ' + node.meta.statusNote.slice(0, 80) : ''}`);

    // Live data text (below node)
    ng.append('text').attr('class', 'live-data').attr('text-anchor', 'middle')
      .attr('y', hh + 14).attr('fill', EDGE_STATUS.pulse).attr('font-size', 9)
      .text(node.meta.rowCount != null && (node.type === 'store_db' || node.type === 'store_json') ? `${node.meta.rowCount} ${node.meta.countLabel || 'rows'}` :
            node.meta.rowCount != null && node.type === 'worker' ? `${node.meta.rowCount} runs` :
            node.meta.fileSize ? `${(node.meta.fileSize/1024).toFixed(1)} KB` : '');

    // Unexpected badge
    if (!node.expected) {
      ng.append('text').attr('x', hw - 12).attr('y', -hh + 14)
        .attr('font-size', 10).attr('fill', OVERLAY_COLORS.unexpected).text('?');
    }

    // Opacity for missing/idle (deprecated nodes already styled above)
    if (node.deprecated) { /* already set to 0.3 above */ }
    else if (!node.signals.exists) ng.style('opacity', '0.35');
    else if (!node.signals.active) ng.style('opacity', '0.65');

    // Drag + click
    let dragDist = 0;
    const drag = d3.drag()
      .on('start', function(this: SVGGElement, ev: any) {
        dragDist = 0;
        ev.sourceEvent.stopPropagation();
        d3.select(this).attr('cursor', 'grabbing').raise();
        hideTooltip();
      })
      .on('drag', function(this: SVGGElement, ev: any) {
        dragDist += Math.abs(ev.dx) + Math.abs(ev.dy);
        node.x = ev.x; node.y = ev.y;
        d3.select(this).attr('transform', `translate(${ev.x},${ev.y})`);
        updateDetach(node, nodes);
        refreshSubgraphs(mainG, nodes, edges, nodeMap);
        refreshEdges(mainG, edges, nodeMap);
      })
      .on('end', function(this: SVGGElement) {
        d3.select(this).attr('cursor', 'pointer');
        if (dragDist < 4) {
          // Click → detail panel
          mainG.selectAll('.shape-main').attr('stroke-width', 2);
          d3.select(this).select('.shape-main').attr('stroke-width', 3.5);
          openSidePanel(node);
        } else {
          markDirty();
        }
      });
    ng.call(drag);

    // Hover glow
    ng.on('mouseenter', function(this: SVGGElement, event: MouseEvent) {
      d3.select(this).select('.shape-main').transition().duration(120).attr('stroke-width', 3);
      showTooltip(event, nodeTooltipHtml(node));
    }).on('mousemove', (event: MouseEvent) => {
      tooltip.style.left = event.pageX + 12 + 'px';
      tooltip.style.top = event.pageY + 12 + 'px';
    }).on('mouseleave', function(this: SVGGElement) {
      const sw = d3.select(this).select('.shape-main').attr('stroke-width');
      if (sw !== '3.5') d3.select(this).select('.shape-main').transition().duration(120).attr('stroke-width', 2);
      hideTooltip();
    });
  }
}

// ── Render ──────────────────────────────────────────────────

function render(data: GraphData) {
  currentData = data;
  mainG.selectAll('*').remove();

  const nodes = data.nodes.map(enrichNode);
  const nodeMap = new Map(nodes.map(n => [n.id, n]));

  layoutNodes(nodes);

  // SVG defs
  const defs = mainG.append('defs');

  // Arrow markers — colors from EDGE_COLORS / EDGE_STATUS palette
  for (const [et, color] of Object.entries(EDGE_COLORS)) {
    defs.append('marker').attr('id', `arrow-${et}`)
      .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
      .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
      .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', color);
  }
  // Status-specific arrows
  defs.append('marker').attr('id', 'arrow-broken')
    .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
    .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
    .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', EDGE_STATUS.broken);
  defs.append('marker').attr('id', 'arrow-deprecated')
    .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
    .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
    .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', EDGE_STATUS.deprecated);

  // Status-specific pulse arrows (for colored pulse buttons)
  for (const [status, color] of Object.entries(STATUS_PULSE_COLORS)) {
    defs.append('marker').attr('id', `arrow-pulse-${status}`)
      .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
      .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
      .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', color);
  }

  // Edge glow filter
  const glowF = defs.append('filter').attr('id', 'edge-glow').attr('filterUnits', 'userSpaceOnUse')
    .attr('x', '-50%').attr('y', '-50%').attr('width', '200%').attr('height', '200%');
  glowF.append('feGaussianBlur').attr('in', 'SourceGraphic').attr('stdDeviation', 2.5).attr('result', 'blur');
  const glowM = glowF.append('feMerge');
  glowM.append('feMergeNode').attr('in', 'blur');
  glowM.append('feMergeNode').attr('in', 'SourceGraphic');

  defs.append('marker').attr('id', 'arrow-active')
    .attr('viewBox', '0 0 10 10').attr('refX', 10).attr('refY', 5)
    .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto-start-reverse')
    .append('path').attr('d', 'M0,0 L10,5 L0,10 Z').attr('fill', EDGE_STATUS.pulse);

  // Compute which tiers each node touches (via edges)
  nodeTiersTouched = new Map<string, Set<number>>();
  for (const n of nodes) {
    nodeTiersTouched.set(n.id, new Set([n.tier]));
  }
  for (const e of data.edges) {
    const src = nodeMap.get(e.sourceId), tgt = nodeMap.get(e.targetId);
    if (src && tgt && src.tier !== tgt.tier) {
      nodeTiersTouched.get(src.id)!.add(tgt.tier);
      nodeTiersTouched.get(tgt.id)!.add(src.tier);
    }
  }

  // Update trigger sublabels now that tiersTouched is computed
  for (const n of nodes) {
    if (n.type === 'trigger') n.sublabel = nodeSublabel(n);
  }

  // Create gradient defs for multi-tier nodes
  for (const [nid, tiers] of nodeTiersTouched) {
    if (tiers.size < 2) continue;
    const sorted = [...tiers].sort();
    const gradId = `grad-${sorted.join('-')}`;
    if (!defs.select(`#${gradId}`).empty()) continue; // already exists
    const grad = defs.append('linearGradient').attr('id', gradId)
      .attr('x1', '0%').attr('y1', '0%').attr('x2', '100%').attr('y2', '100%');
    const colors = sorted.map(t => TIER_COLORS[t] || TIER_COLOR_DEFAULT);
    const step = 100 / colors.length;
    colors.forEach((c, i) => {
      grad.append('stop').attr('offset', `${i * step}%`).attr('stop-color', c);
      grad.append('stop').attr('offset', `${(i + 1) * step}%`).attr('stop-color', c);
    });
  }

  // Draw order: subgraphs+edges → nodes → active-edges (Z layers)
  // Subgraphs go directly on mainG (background), edges/nodes/active in sub-layers
  drawSubgraphs(mainG, nodes, data.edges, nodeMap);
  edgeLayer = mainG.append('g').attr('class', 'layer-edges');
  nodeLayer = mainG.append('g').attr('class', 'layer-nodes');
  activeEdgeLayer = mainG.append('g').attr('class', 'layer-active-edges');
  drawEdges(edgeLayer, data.edges, nodeMap);
  drawNodes(nodeLayer, nodes, data.edges, nodeMap);

  // Layer labels (subtle)
  for (const [layer, y] of Object.entries(LAYER_Y)) {
    const label = LAYER_LABELS[Number(layer)];
    if (!label) continue;
    mainG.append('text')
      .attr('x', -nodes.length * 85 - 60).attr('y', y + 4)
      .attr('fill', '#333').attr('font-size', 10).attr('font-weight', 600)
      .text(label);
  }

  // Summary bar
  updateSummaryBar(data);
}

// Cached health data — refreshed every 15s in background
let _healthCache: any = null;

function refreshHealthCache() {
  fetch('/api/daemon-health').then(r => r.json()).then(d => {
    _healthCache = d;
    // Re-render summary bar with fresh health data
    if (currentData) updateSummaryBar(currentData);
  }).catch(() => {});
}
// Start immediately, repeat every 15s
refreshHealthCache();
setInterval(refreshHealthCache, 15000);

function updateSummaryBar(data: GraphData) {
  const tierLabels = ['', 'T1 Reactive', 'T2 Adaptive', 'T3 Deliberative'];
  const tierTips = [
    '',
    'T1 Reactive: CJS hooks layer (intelligence.cjs, PageRank, JSON files). Fast (<15ms), self-contained.',
    'T2 Adaptive: 28 AgentDB controllers across 6 levels. ESM, memory-bridge, memory.db.',
    'T3 Deliberative: ruvector IntelligenceEngine, HNSW vector index, ONNX 384D embeddings.',
  ];
  let html = '';

  // Tiers (from graph data)
  for (let t = 1; t <= 3; t++) {
    const tier = data.summary.tiers[t];
    if (!tier) continue;
    html += `<div class="tier" title="${tierTips[t]} ${tier.activeCount} of ${tier.nodeCount} active."><span class="tier-dot ${tier.status}"></span>${tierLabels[t]}: ${tier.activeCount}/${tier.nodeCount}</div>`;
  }

  // Health (from cached daemon-health — refreshed every 15s in background)
  {
    const h = _healthCache;
    if (h) {
      const p = h.pipeline || {};
      const q = h.qtable || {};
      const daemonList = Object.entries(h.daemons || {}) as [string, any][];
      const daemonTip = daemonList.map(([k, v]) => `${v ? '\u2713' : '\u2717'} ${k}`).join(', ');
      const badges = daemonList.map(([k, v]) => {
        const on = !!v;
        const c = on ? '#22c55e' : '#ef4444';
        const dot = on ? '\u25CF' : '\u25CB';
        const short = k.replace('-daemon', '').replace('-monitor', '-mon');
        return `<span style="color:${c}" title="${k}: ${on ? 'RUNNING' : 'STOPPED'}">${dot} ${short}</span>`;
      }).join(' ');
      html += `<div class="tier" title="Daemons: ${daemonTip}">${badges}</div>`;
      html += `<div class="tier"><span title="Total bridge operations (T2 writes, consolidations, L1 promotions)">ops:${p.totalPipelineOps||0}</span> &middot; <span title="Q-table routing patterns (state-action pairs)">Q:${q.entries||0}</span> &middot; <span title="Vector memories in ruvector.db (HNSW search)">mem:${q.memories||0}</span></div>`;
    }
  }

  // Counts
  html += `<div class="tier" style="margin-left:auto"><span title="Nodes found on disk">${data.summary.foundCount} found</span> &middot; <span title="Expected nodes not found (red dots)">${data.summary.missingCount} missing</span> &middot; <span title="Last refresh">${new Date().toLocaleTimeString()}</span></div>`;

  const bar = document.getElementById('summary-bar');
  if (bar) bar.innerHTML = html;
}

// ── Edge Pulse System ───────────────────────────────────────

function applyEdgeVisual(idx: number, energy: number, now: number) {
  const eG = mainG.select(`.edge-${idx}`);
  if (eG.empty()) return;
  const path = eG.select('.edge-path');
  if (!path.node()) return;

  if (energy <= 0) {
    const d = currentData?.edges[idx];
    const restColor = d ? edgeStrokeColor(d) : EDGE_COLOR_DEFAULT;
    const restOpacity = d ? edgeOpacity(d) : EDGE_OPACITY.idle;
    path.attr('stroke', restColor)
      .attr('stroke-width', d?.deprecated ? 1 : 1.5).attr('stroke-dasharray', d?.deprecated ? '4,4' : 'none').attr('stroke-dashoffset', 0)
      .attr('filter', null).attr('opacity', restOpacity)
      .attr('marker-end', d ? edgeArrowUrl(d) : 'url(#arrow-calls)');
    // Reset hit area back to transparent (pulse may have colored it)
    eG.select('.edge-hit').attr('stroke', 'transparent').attr('filter', null);
    // Move back to normal edge layer (behind nodes)
    if (raisedEdges.has(idx) && edgeLayer) {
      edgeLayer.node().appendChild(eG.node());
    }
    return;
  }

  const brightness = 0.5 + energy * 0.5;
  const width = 1.5 + energy * 2.5;
  const offset = -(now * 0.04) % 24;

  // Move pulsed edge to active layer (in front of nodes)
  if (!raisedEdges.has(idx)) { raisedEdges.add(idx); if (activeEdgeLayer) activeEdgeLayer.node().appendChild(eG.node()); else eG.raise(); }

  const pulseColor = edgePulseColor.get(idx) || EDGE_STATUS.pulse;
  // Match arrow marker to pulse color
  const arrowId = Object.entries(STATUS_PULSE_COLORS).find(([, c]) => c === pulseColor)?.[0];
  const markerRef = arrowId ? `url(#arrow-pulse-${arrowId})` : 'url(#arrow-active)';
  path.attr('stroke', pulseColor).attr('stroke-width', width)
    .attr('stroke-dasharray', '8,4').attr('stroke-dashoffset', offset)
    .attr('filter', energy > 0.1 ? 'url(#edge-glow)' : null)
    .attr('opacity', brightness).attr('marker-end', markerRef);
}

// ── Node Pulse Visual (store glow on read/write) ────────────

function applyNodeVisual(nodeId: string, energy: number, now: number) {
  const nG = mainG.select(`.node-${nodeId}`);
  if (nG.empty()) return;
  const shape = nG.select('.shape-main');
  if (!shape.node()) return;
  const node: GraphNode | undefined = nG.datum();

  if (energy <= 0) {
    // Reset to resting state — border = node type color
    if (node) {
      const style = STYLE[node.type] || STYLE.config;
      shape.attr('stroke', style.stroke).attr('stroke-width', 2);
    }
    nG.style('filter', 'drop-shadow(0 2px 4px rgba(0,0,0,0.5))');
    // Reset scale
    if (node && node.x != null && node.y != null) {
      nG.attr('transform', `translate(${node.x},${node.y})`);
    }
    return;
  }

  // Glow: brighten border to cyan, widen stroke, add glow filter
  const glowIntensity = 0.4 + energy * 0.6;
  const strokeW = 2 + energy * 2.5;
  // Pulsating inner brightness via a subtle scale bounce
  const scale = 1.0 + energy * 0.03 * Math.sin(now * 0.006);
  shape.attr('stroke', EDGE_STATUS.pulse).attr('stroke-width', strokeW);
  nG.style('filter', energy > 0.1
    ? `drop-shadow(0 0 ${4 + energy * 8}px rgba(34,211,238,${glowIntensity}))`
    : 'drop-shadow(0 2px 4px rgba(0,0,0,0.5))');
  // Gentle scale pulse on the whole node group
  const d = nG.datum() as GraphNode;
  if (d?.x != null && d?.y != null) {
    nG.attr('transform', `translate(${d.x},${d.y}) scale(${scale.toFixed(4)})`);
  }
}

function startEnergyLoop() {
  if (rafId) cancelAnimationFrame(rafId);
  let lastFrame = 0;
  const loop = (now: number) => {
    rafId = requestAnimationFrame(loop);
    if (now - lastFrame < 33) return;
    lastFrame = now;
    if (edgeEnergy.size === 0 && nodeEnergy.size === 0) return;
    for (const [idx, energy] of edgeEnergy) {
      const next = energy * 0.982;
      if (next < 0.02) {
        edgeEnergy.delete(idx);
        edgePulseColor.delete(idx);
        applyEdgeVisual(idx, 0, now); // moves edge back to edgeLayer
        raisedEdges.delete(idx);
      } else {
        edgeEnergy.set(idx, next);
        applyEdgeVisual(idx, next, now);
      }
    }
    // Decay + render store node glow
    for (const [nid, energy] of nodeEnergy) {
      const next = energy * 0.978;
      if (next < 0.02) {
        nodeEnergy.delete(nid);
        applyNodeVisual(nid, 0, now);
      } else {
        nodeEnergy.set(nid, next);
        applyNodeVisual(nid, next, now);
      }
    }
  };
  rafId = requestAnimationFrame(loop);
}

let firstPoll = true;
async function pollTranscript() {
  if (!edgeIndexMap) return;
  try {
    let url: string;
    if (pulseScope === 'all') {
      url = '/api/activity-stream?scope=all&tail=1';
    } else if (firstPoll) {
      // First poll: just grab the current offset, don't replay history
      url = '/api/activity-stream?tail=1&skip=1';
    } else {
      url = `/api/activity-stream?offset=${transcriptOffset}`;
    }
    firstPoll = false;
    const data = await (await fetch(url)).json();
    if (data.offset) transcriptOffset = data.offset;
    // On skip=1 response, only set offset — don't process stale lines
    if (!data.skipped && data.lines?.length) processLines(data.lines);
  } catch {}
}

function resetEdgeLayers() {
  // Move all raised edges back to normal edge layer
  if (edgeLayer && activeEdgeLayer) {
    for (const idx of raisedEdges) {
      const eG = mainG.select(`.edge-${idx}`);
      if (!eG.empty()) edgeLayer.node().appendChild(eG.node());
    }
  }
  raisedEdges.clear();
}

function startPulseSystem() {
  if (pulseTimer) clearInterval(pulseTimer);
  edgeEnergy.clear(); nodeEnergy.clear(); resetEdgeLayers();
  _processedLineHashes.clear(); _signalPulsedNodes.clear(); // V05: reset dedup state
  firstPoll = true; transcriptOffset = 0;
  startEnergyLoop();
  pollTranscript();
  pulseTimer = setInterval(pollTranscript, 1500);
}

// ── Layout Persistence ──────────────────────────────────────

function markDirty() {
  const btn = document.getElementById('save-layout-btn');
  if (btn) btn.classList.add('dirty');
}

export async function saveLayout() {
  if (!currentData) return;
  const positions: Record<string, { x: number; y: number }> = {};
  for (const n of currentData.nodes) {
    if (n.x != null && n.y != null) positions[n.id] = { x: n.x, y: n.y };
  }
  savedPositions = positions;
  // Capture current zoom/pan transform
  const t = d3.zoomTransform(svg.node());
  const transform = { x: t.x, y: t.y, k: t.k };
  try {
    await fetch('/api/layout', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ positions, detached: [...detachedNodes], transform }),
    });
    const btn = document.getElementById('save-layout-btn');
    if (btn) {
      btn.classList.remove('dirty');
      btn.textContent = '\u2713 Saved';
      setTimeout(() => { btn.textContent = 'Save Layout'; }, 1200);
    }
  } catch {}
}

export async function resetLayout() {
  // Try to restore last saved layout from server
  try {
    const lr = await fetch('/api/layout');
    const ld = await lr.json();
    if (ld.positions && Object.keys(ld.positions).length > 0) {
      savedPositions = ld.positions;
      detachedNodes.clear();
      satelliteGroups.clear();
      liveSatelliteSvgs.clear();
      if (Array.isArray(ld.detached)) {
        for (const id of ld.detached) detachedNodes.add(id);
      }
      if (currentData) render(currentData);
      if (detachedNodes.size > 0 && currentData) {
        const groups = new Set(currentData.nodes.filter(n => detachedNodes.has(n.id)).map(n => n.group));
        for (const g of groups) rebuildSatellites(g, currentData.nodes);
        refreshSubgraphs(mainG, currentData.nodes, currentData.edges,
          new Map(currentData.nodes.map(n => [n.id, n])));
      }
      if (ld.transform && typeof ld.transform.k === 'number') {
        const t = d3.zoomIdentity.translate(ld.transform.x, ld.transform.y).scale(ld.transform.k);
        svg.call(zoomBehavior.transform, t);
      }
      return;
    }
  } catch {}

  // Fallback: no saved layout — reset to auto-layout
  savedPositions = {};
  detachedNodes.clear();
  satelliteGroups.clear();
  liveSatelliteSvgs.clear();
  if (svg && zoomBehavior) svg.call(zoomBehavior.transform, d3.zoomIdentity);
  if (currentData) render(currentData);
}

export function toggleBoxes() {
  showBoxes = !showBoxes;
  if (!mainG) return;
  for (const sg of SUBGRAPHS) {
    mainG.select(`.sg-${sg.id}`).select('.sg-bg').attr('opacity', showBoxes ? 0.3 : 0);
    mainG.select(`.sg-${sg.id}`).select('.sg-label').attr('opacity', showBoxes ? 1 : 0);
  }
  // Toggle satellite visibility
  mainG.selectAll('.satellite-group').attr('display', showBoxes ? null : 'none');
}

export function togglePulseScope() {
  pulseScope = pulseScope === 'project' ? 'all' : 'project';
  // Reset poll state so we don't send stale offsets
  firstPoll = true;
  transcriptOffset = 0;
  edgeEnergy.clear(); nodeEnergy.clear();
  resetEdgeLayers();
  _cascadeVisited.clear();
  _processedLineHashes.clear(); _signalPulsedNodes.clear(); // V05: reset dedup state
  return pulseScope;
}

// Replay session history — one-time tail read of the full JSONL
export async function replaySession() {
  if (!edgeIndexMap) return;
  edgeEnergy.clear(); nodeEnergy.clear();
  resetEdgeLayers();
  _cascadeVisited.clear();
  _processedLineHashes.clear(); _signalPulsedNodes.clear(); // V05: allow replay to re-process all lines
  try {
    const url = pulseScope === 'all'
      ? '/api/activity-stream?scope=all&tail=1'
      : '/api/activity-stream?tail=1';
    const data = await (await fetch(url)).json();
    if (data.offset) transcriptOffset = data.offset;
    if (data.lines?.length) processLines(data.lines);
  } catch {}
}

// ── Filter Panel (IT094-style collapsible left panel) ────────

function isNodeHidden(n: GraphNode): boolean {
  if (hiddenGroups.has(n.group)) return true;
  if (hiddenNodes.has(n.id)) return true;
  if (!showExpected && n.expected) return true;
  if (!showUnexpected && !n.expected) return true;
  // Filter by primary tier — multi-tier dots are informational only
  if (hiddenTiers.has(n.tier)) return true;
  return false;
}

function applyVisibility() {
  if (!mainG || !currentData) return;
  const nodeMap = new Map(currentData.nodes.map(n => [n.id, n]));

  for (const node of currentData.nodes) {
    mainG.select(`.node-${node.id}`).attr('display', isNodeHidden(node) ? 'none' : null);
  }

  currentData.edges.forEach((edge, idx) => {
    const src = nodeMap.get(edge.sourceId), tgt = nodeMap.get(edge.targetId);
    const srcHidden = src && isNodeHidden(src);
    const tgtHidden = tgt && isNodeHidden(tgt);
    mainG.select(`.edge-${idx}`).attr('display', (srcHidden || tgtHidden) ? 'none' : null);
  });

  for (const sg of SUBGRAPHS) {
    const members = currentData.nodes.filter(n => n.group === sg.id);
    const allHidden = hiddenGroups.has(sg.id) || members.every(n => isNodeHidden(n));
    mainG.select(`.sg-${sg.id}`).attr('display', allHidden ? 'none' : null);
  }
}

function buildFilterTree() {
  if (!filterPanel || !currentData) return;
  filterPanel.innerHTML = '';
  const nodes = currentData.nodes;

  // Header + quick buttons
  const header = document.createElement('div');
  header.style.cssText = 'margin-bottom:10px';
  header.innerHTML = `<div style="font-size:12px;font-weight:bold;color:#f8fafc;margin-bottom:8px">Layers</div>`;
  const btnRow = document.createElement('div');
  btnRow.style.cssText = 'display:flex;gap:1px;background:#334155;border-radius:6px;overflow:hidden';
  for (const [label, action] of [
    ['All On', () => { hiddenGroups.clear(); hiddenNodes.clear(); hiddenTiers.clear(); showExpected = true; showUnexpected = true; buildFilterTree(); applyVisibility(); }],
    ['All Off', () => { for (const cat of FILTER_CATEGORIES) for (const g of cat.groups) hiddenGroups.add(g.id); hiddenTiers.add(0); hiddenTiers.add(1); hiddenTiers.add(2); hiddenTiers.add(3); hiddenTiers.add(9); showExpected = false; showUnexpected = false; buildFilterTree(); applyVisibility(); }],
    ['Expand', () => { for (const cat of FILTER_CATEGORIES) { openCategories.add(cat.label); for (const g of cat.groups) openNodeLists.add(g.id); } buildFilterTree(); }],
    ['Collapse', () => { openCategories.clear(); openNodeLists.clear(); buildFilterTree(); }],
  ] as [string, () => void][]) {
    const b = document.createElement('button');
    b.textContent = label;
    b.style.cssText = 'flex:1;background:#1e293b;color:#94a3b8;border:none;padding:5px 2px;font-size:9px;cursor:pointer;font-family:inherit';
    b.addEventListener('mouseenter', () => { b.style.background = '#334155'; b.style.color = '#f8fafc'; });
    b.addEventListener('mouseleave', () => { b.style.background = '#1e293b'; b.style.color = '#94a3b8'; });
    b.addEventListener('click', action);
    btnRow.appendChild(b);
  }
  header.appendChild(btnRow);
  filterPanel.appendChild(header);

  // Divider
  const div1 = document.createElement('div');
  div1.style.cssText = 'height:1px;background:#334155;margin-bottom:8px';
  filterPanel.appendChild(div1);

  // Cycle / Tier filter
  const tierEl = document.createElement('div');
  tierEl.style.cssText = 'margin-bottom:10px';
  tierEl.innerHTML = `<div style="font-size:11px;font-weight:bold;color:#f8fafc;margin-bottom:6px">Cycles</div>`;

  const tierDefs: [number, string, string, string][] = [
    [0, 'T0 Infrastructure', TIER_COLORS[0] || TIER_COLOR_DEFAULT, 'Shared infra: memory DB, daemon, viz'],
    [1, 'T1 Reactive',       TIER_COLORS[1], 'Hook-driven, <1ms, PageRank context'],
    [2, 'T2 Adaptive',       TIER_COLORS[2], 'Online learning, ONNX, ~100ms'],
    [3, 'T3 Deliberative',   TIER_COLORS[3], 'Reasoning, MCP, ControllerRegistry'],
    [9, 'CLI / Utilities',   TIER_COLORS[9], 'Unexpected scripts, not in registry'],
  ];

  for (const [tier, label, color, desc] of tierDefs) {
    const count = nodes.filter(n => n.tier === tier).length;
    if (count === 0) continue;
    const row = document.createElement('div');
    row.style.cssText = 'display:flex;align-items:center;gap:6px;padding:2px 0';
    const cb = document.createElement('input');
    cb.type = 'checkbox';
    cb.checked = !hiddenTiers.has(tier);
    cb.style.cssText = `accent-color:${color};cursor:pointer;width:12px;height:12px`;
    cb.addEventListener('change', () => {
      if (cb.checked) hiddenTiers.delete(tier); else hiddenTiers.add(tier);
      applyVisibility(); buildFilterTree();
    });
    row.appendChild(cb);
    const dot = document.createElement('span');
    dot.style.cssText = `display:inline-block;width:8px;height:8px;border-radius:50%;background:${color}`;
    row.appendChild(dot);
    const lbl = document.createElement('span');
    lbl.style.cssText = `font-size:10px;color:${!hiddenTiers.has(tier) ? color : '#555'}`;
    lbl.title = desc;
    lbl.textContent = `${label} (${count})`;
    row.appendChild(lbl);
    tierEl.appendChild(row);
  }
  filterPanel.appendChild(tierEl);

  // Divider
  const divT = document.createElement('div');
  divT.style.cssText = 'height:1px;background:#334155;margin-bottom:8px';
  filterPanel.appendChild(divT);

  // Status filter (Expected / Unexpected)
  const statusEl = document.createElement('div');
  statusEl.style.cssText = 'margin-bottom:10px';
  statusEl.innerHTML = `<div style="font-size:11px;font-weight:bold;color:#f8fafc;margin-bottom:6px">Status</div>`;

  const expCount = nodes.filter(n => n.expected).length;
  const unexpCount = nodes.filter(n => !n.expected).length;

  for (const [label, count, color, getter, setter] of [
    ['Expected', expCount, STATUS_DOT.active, () => showExpected, (v: boolean) => { showExpected = v; }],
    ['Unexpected', unexpCount, '#06b6d4', () => showUnexpected, (v: boolean) => { showUnexpected = v; }],
  ] as [string, number, string, () => boolean, (v: boolean) => void][]) {
    const row = document.createElement('div');
    row.style.cssText = 'display:flex;align-items:center;gap:6px;padding:2px 0';
    const cb = document.createElement('input');
    cb.type = 'checkbox';
    cb.checked = getter();
    cb.style.cssText = `accent-color:${color};cursor:pointer;width:12px;height:12px`;
    cb.addEventListener('change', () => { setter(cb.checked); applyVisibility(); buildFilterTree(); });
    row.appendChild(cb);
    const dot = document.createElement('span');
    dot.style.cssText = `display:inline-block;width:8px;height:8px;border-radius:50%;background:${color}`;
    row.appendChild(dot);
    const lbl = document.createElement('span');
    lbl.style.cssText = `font-size:10px;color:${getter() ? color : '#555'}`;
    lbl.textContent = `${label} (${count})`;
    row.appendChild(lbl);
    statusEl.appendChild(row);
  }
  filterPanel.appendChild(statusEl);
  const div2 = document.createElement('div');
  div2.style.cssText = 'height:1px;background:#334155;margin-bottom:8px';
  filterPanel.appendChild(div2);

  // Categories
  for (const cat of FILTER_CATEGORIES) {
    const catEl = document.createElement('div');
    catEl.style.cssText = 'margin-bottom:6px';

    // Category header (collapsible)
    const catHeader = document.createElement('div');
    catHeader.style.cssText = 'display:flex;align-items:center;gap:4px;cursor:pointer;padding:3px 0;color:#f8fafc;font-size:11px;font-weight:bold';
    const arrow = document.createElement('span');
    arrow.style.cssText = 'font-size:8px;transition:transform 0.2s;display:inline-block';
    arrow.textContent = '\u25B6';
    catHeader.appendChild(arrow);
    catHeader.appendChild(document.createTextNode(cat.label));

    const catOpen = openCategories.has(cat.label);
    const catBody = document.createElement('div');
    catBody.style.cssText = `display:${catOpen ? 'block' : 'none'};padding-left:8px`;
    if (catOpen) arrow.style.transform = 'rotate(90deg)';
    catHeader.addEventListener('click', () => {
      const isOpen = openCategories.has(cat.label);
      if (isOpen) openCategories.delete(cat.label); else openCategories.add(cat.label);
      catBody.style.display = isOpen ? 'none' : 'block';
      arrow.style.transform = isOpen ? '' : 'rotate(90deg)';
    });
    catEl.appendChild(catHeader);

    // Groups within category
    for (const grp of cat.groups) {
      const members = nodes.filter(n => n.group === grp.id);
      if (members.length === 0) continue;
      const groupHidden = hiddenGroups.has(grp.id);
      const hiddenCount = members.filter(n => hiddenNodes.has(n.id)).length;

      const grpRow = document.createElement('div');
      grpRow.style.cssText = 'display:flex;align-items:center;gap:4px;padding:2px 0';

      const cb = document.createElement('input');
      cb.type = 'checkbox';
      cb.checked = !groupHidden;
      cb.indeterminate = !groupHidden && hiddenCount > 0 && hiddenCount < members.length;
      cb.style.cssText = `accent-color:${grp.color};cursor:pointer;width:12px;height:12px`;
      cb.addEventListener('change', () => {
        if (cb.checked) { hiddenGroups.delete(grp.id); for (const m of members) hiddenNodes.delete(m.id); }
        else hiddenGroups.add(grp.id);
        applyVisibility(); buildFilterTree();
      });
      grpRow.appendChild(cb);

      const grpLabel = document.createElement('span');
      grpLabel.style.cssText = `font-size:10px;color:${groupHidden ? '#555' : grp.color};cursor:pointer;flex:1`;
      grpLabel.textContent = `${grp.label} (${members.length})`;
      grpRow.appendChild(grpLabel);

      // Node list expand arrow
      const nodeArrow = document.createElement('span');
      nodeArrow.style.cssText = 'font-size:7px;color:#94a3b8;cursor:pointer;padding:2px 4px';
      nodeArrow.textContent = '\u25B6';
      grpRow.appendChild(nodeArrow);
      catBody.appendChild(grpRow);

      // Node list
      const nlOpen = openNodeLists.has(grp.id);
      const nodeList = document.createElement('div');
      nodeList.style.cssText = `display:${nlOpen ? 'block' : 'none'};padding-left:20px`;
      if (nlOpen) nodeArrow.style.transform = 'rotate(90deg)';
      const toggleNL = (e: Event) => {
        e.stopPropagation();
        const isOpen = openNodeLists.has(grp.id);
        if (isOpen) openNodeLists.delete(grp.id); else openNodeLists.add(grp.id);
        nodeList.style.display = isOpen ? 'none' : 'block';
        nodeArrow.style.transform = isOpen ? '' : 'rotate(90deg)';
      };
      nodeArrow.addEventListener('click', toggleNL);
      grpLabel.addEventListener('click', toggleNL);

      for (const node of members) {
        const nodeHidden = groupHidden || hiddenNodes.has(node.id);
        const nodeRow = document.createElement('div');
        nodeRow.style.cssText = 'display:flex;align-items:center;gap:4px;padding:1px 0';
        const ncb = document.createElement('input');
        ncb.type = 'checkbox';
        ncb.checked = !nodeHidden;
        ncb.disabled = groupHidden;
        ncb.style.cssText = 'cursor:pointer;width:10px;height:10px';
        ncb.addEventListener('change', () => {
          if (ncb.checked) hiddenNodes.delete(node.id); else hiddenNodes.add(node.id);
          applyVisibility(); buildFilterTree();
        });
        nodeRow.appendChild(ncb);

        const style = STYLE[node.type] || STYLE.config;
        const dot = document.createElement('span');
        dot.style.cssText = `display:inline-block;width:6px;height:6px;border-radius:50%;background:${nodeHidden ? '#444' : style.stroke}`;
        nodeRow.appendChild(dot);

        const nlbl = document.createElement('span');
        nlbl.style.cssText = `font-size:9px;color:${nodeHidden ? '#555' : '#94a3b8'};white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:160px`;
        nlbl.textContent = node.sublabel ? `${node.label} ${node.sublabel}` : node.label;
        nodeRow.appendChild(nlbl);

        if (!node.expected) {
          const badge = document.createElement('span');
          badge.style.cssText = 'font-size:7px;color:#06b6d4;margin-left:2px';
          badge.textContent = '?';
          badge.title = 'Unexpected — not in architecture registry';
          nodeRow.appendChild(badge);
        }
        nodeList.appendChild(nodeRow);
      }
      catBody.appendChild(nodeList);
    }

    catEl.appendChild(catBody);
    filterPanel.appendChild(catEl);
  }
}

let filterVisible = false;
const FILTER_CSS = 'position:absolute;top:94px;right:8px;z-index:7;background:#1e293bee;border:1px solid #334155;border-radius:8px;padding:12px 16px;font-size:11px;color:#e2e8f0;width:240px;box-shadow:0 4px 16px rgba(0,0,0,0.5);max-height:calc(100vh - 200px);overflow-y:auto;display:none;';

export function toggleFilter() {
  if (!filterPanel) {
    filterPanel = document.createElement('div');
    filterPanel.id = 'graph-filter';
    document.getElementById('graph-view')!.appendChild(filterPanel);
  }
  // Always reapply position styles (clears any stale left-panel layout)
  filterPanel.style.cssText = FILTER_CSS;
  filterVisible = !filterVisible;
  if (filterVisible) {
    // Close legend if open
    if (legendVisible) {
      legendVisible = false;
      const legend = document.getElementById('graph-legend');
      if (legend) legend.style.display = 'none';
      document.getElementById('legend-btn')?.classList.remove('active');
    }
    buildFilterTree();
  }
  filterPanel.style.display = filterVisible ? 'block' : 'none';
}

// ── Legend Panel ─────────────────────────────────────────────

let legendVisible = false;

export function toggleLegend() {
  legendVisible = !legendVisible;
  if (legendVisible) {
    // Close filter if open
    if (filterVisible) {
      filterVisible = false;
      if (filterPanel) filterPanel.style.display = 'none';
      document.getElementById('filter-btn')?.classList.remove('active');
    }
  }
  let panel = document.getElementById('graph-legend');
  if (!panel) {
    panel = document.createElement('div');
    panel.id = 'graph-legend';
    panel.style.cssText = `
      position:absolute; top:94px; right:8px; z-index:6;
      background:#1e293bee; border:1px solid #334155; border-radius:8px;
      padding:12px 16px; font-size:11px; color:#e2e8f0; width:240px;
      box-shadow:0 4px 16px rgba(0,0,0,0.5); max-height:calc(100vh - 200px); overflow-y:auto;
    `;
    document.getElementById('graph-view')!.appendChild(panel);
  }
  // Rebuild legend contents each time (reflects current palette)
  buildLegendPanel(panel);
  panel.style.display = legendVisible ? 'block' : 'none';
}

function buildLegendPanel(panel: HTMLElement) {
  const pickerCSS = 'width:20px;height:14px;border:1px solid #555;border-radius:2px;padding:0;cursor:pointer;background:none;';
  const rowCSS = 'display:flex;align-items:center;gap:6px;margin-bottom:3px';

  let html = '<div style="font-weight:600;margin-bottom:8px;font-size:12px;color:#f8fafc">Legend <span style="color:#64748b;font-weight:400">(editable)</span></div>';

  // Node types (read-only shapes)
  html += '<div style="font-weight:600;margin-bottom:4px;color:#94a3b8">Node Types</div>';
  const nodeTypes = [
    { type: 'trigger', shape: 'parallelogram', label: 'Hook Trigger' },
    { type: 'script', shape: 'rect', label: 'Hook Script' },
    { type: 'engine', shape: 'rect', label: 'Engine' },
    { type: 'store_db', shape: 'cylinder', label: 'Database' },
    { type: 'store_json', shape: 'rect', label: 'JSON Store' },
    { type: 'config', shape: 'rect', label: 'Config' },
    { type: 'model', shape: 'rect', label: 'Model' },
    { type: 'service', shape: 'rect', label: 'MCP Service' },
  ];
  for (const nt of nodeTypes) {
    const s = STYLE[nt.type];
    let shapeStyle = `display:inline-block;width:16px;height:10px;background:${s.fill};border:2px solid ${s.stroke};`;
    if (nt.shape === 'parallelogram') shapeStyle += 'transform:skewX(-12deg);border-radius:2px;';
    else if (nt.shape === 'cylinder') shapeStyle += 'border-radius:50%/25%;';
    else shapeStyle += 'border-radius:2px;';
    html += `<div style="${rowCSS}"><span style="${shapeStyle}"></span><span style="color:${s.text}">${nt.label}</span></div>`;
  }

  // Edge types — editable color pickers
  html += '<div style="font-weight:600;margin:8px 0 4px;color:#94a3b8">Edge Types</div>';
  const edgeTypeKeys = ['fires', 'calls', 'reads', 'writes', 'uses', 'loads', 'configures'];
  const edgeTypeLabels: Record<string, string> = { fires: 'Fires', calls: 'Calls', reads: 'Reads', writes: 'Writes', uses: 'Uses', loads: 'Loads', configures: 'Configures' };
  for (const et of edgeTypeKeys) {
    html += `<div style="${rowCSS}"><input type="color" id="lp-edge-${et}" value="${EDGE_COLORS[et]}" style="${pickerCSS}" /><span>${edgeTypeLabels[et]}</span></div>`;
  }
  // Pulse + broken (editable)
  html += `<div style="${rowCSS}"><input type="color" id="lp-pulse" value="${EDGE_STATUS.pulse}" style="${pickerCSS}" /><span>Active (pulse)</span></div>`;
  html += `<div style="${rowCSS}"><input type="color" id="lp-broken" value="${EDGE_STATUS.broken}" style="${pickerCSS}" /><span>Broken</span></div>`;

  // Edge opacity — sliders
  html += '<div style="font-weight:600;margin:8px 0 4px;color:#94a3b8">Edge Opacity</div>';
  const opacityKeys = ['active', 'idle', 'broken', 'deprecated'] as const;
  const opacityLabels: Record<string, string> = { active: 'Active', idle: 'Idle', broken: 'Broken', deprecated: 'Deprecated' };
  for (const ok of opacityKeys) {
    const pct = Math.round(EDGE_OPACITY[ok] * 100);
    html += `<div style="${rowCSS}">
      <input type="range" id="lp-op-${ok}" min="5" max="100" value="${pct}" style="width:50px;height:10px;cursor:pointer;accent-color:#64748b" />
      <span id="lp-op-${ok}-val" style="width:24px;text-align:right;color:#94a3b8">${pct}%</span>
      <span>${opacityLabels[ok]}</span>
    </div>`;
  }

  // Group opacity — dim specific edge groups
  html += '<div style="font-weight:600;margin:8px 0 4px;color:#94a3b8">Group Opacity</div>';
  const groupKeys = ['workers', 'controllers'] as const;
  const groupLabels: Record<string, string> = { workers: 'CLI Tools', controllers: 'ADR-053 Controllers' };
  for (const gk of groupKeys) {
    const pct = Math.round((EDGE_GROUP_OPACITY[gk] ?? 1) * 100);
    html += `<div style="${rowCSS}">
      <input type="range" id="lp-gop-${gk}" min="0" max="100" value="${pct}" style="width:50px;height:10px;cursor:pointer;accent-color:#60a5fa" />
      <span id="lp-gop-${gk}-val" style="width:24px;text-align:right;color:#94a3b8">${pct}%</span>
      <span>${groupLabels[gk]}</span>
    </div>`;
  }

  // Tier dots — small colored circles at bottom-left of each node
  html += '<div style="font-weight:600;margin:8px 0 4px;color:#94a3b8">Tier Dots</div>';
  html += '<div style="font-size:9px;color:#64748b;margin-bottom:4px">Colored dots at each node\'s bottom-left</div>';
  const tierDefs = [
    { tier: 0, label: 'T0 — Infrastructure' }, { tier: 1, label: 'T1 — Reactive' },
    { tier: 2, label: 'T2 — Adaptive' }, { tier: 3, label: 'T3 — Deliberative' },
    { tier: 9, label: 'T9 — Unexpected' },
  ];
  for (const td of tierDefs) {
    html += `<div style="${rowCSS}">
      <input type="color" id="lp-tier-${td.tier}" value="${TIER_COLORS[td.tier]}" style="${pickerCSS}" />
      <span style="display:inline-block;width:7px;height:7px;border-radius:50%;background:${TIER_COLORS[td.tier]};border:1px solid #333"></span>
      <span>${td.label}</span>
    </div>`;
  }

  // Status dots — editable
  html += '<div style="font-weight:600;margin:8px 0 4px;color:#94a3b8">Status Dot</div>';
  const dotKeys = ['active', 'idle', 'unhealthy', 'missing', 'onDemand', 'phantom', 'deprecated'];
  const dotLabels: Record<string, string> = { active: 'Active', idle: 'Idle', unhealthy: 'Unhealthy', missing: 'Missing', onDemand: 'On-demand', phantom: 'Phantom', deprecated: 'Deprecated' };
  for (const dk of dotKeys) {
    html += `<div style="${rowCSS}">
      <input type="color" id="lp-dot-${dk}" value="${STATUS_DOT[dk]}" style="${pickerCSS}" />
      <span>${dotLabels[dk]}</span>
    </div>`;
  }

  // Save / Reset buttons
  html += `<div style="margin-top:12px;display:flex;gap:6px">
    <button id="lp-save" style="flex:1;padding:4px 8px;background:#1d4ed8;color:#fff;border:none;border-radius:4px;cursor:pointer;font-size:10px">Save Theme</button>
    <button id="lp-reset" style="flex:1;padding:4px 8px;background:#334155;color:#e2e8f0;border:none;border-radius:4px;cursor:pointer;font-size:10px">Reset</button>
  </div>
  <div id="lp-status" style="margin-top:4px;font-size:9px;color:#64748b;text-align:center"></div>`;

  panel.innerHTML = html;

  // Wire color picker events — update palette + live preview
  for (const et of edgeTypeKeys) {
    const el = document.getElementById(`lp-edge-${et}`) as HTMLInputElement;
    if (el) el.addEventListener('input', () => { EDGE_COLORS[et] = el.value; applyThemeLive(); });
  }
  const pulseEl = document.getElementById('lp-pulse') as HTMLInputElement;
  if (pulseEl) pulseEl.addEventListener('input', () => { EDGE_STATUS.pulse = pulseEl.value; applyThemeLive(); });
  const brokenEl = document.getElementById('lp-broken') as HTMLInputElement;
  if (brokenEl) brokenEl.addEventListener('input', () => { EDGE_STATUS.broken = brokenEl.value; applyThemeLive(); });

  // Wire opacity sliders
  for (const ok of opacityKeys) {
    const el = document.getElementById(`lp-op-${ok}`) as HTMLInputElement;
    const valEl = document.getElementById(`lp-op-${ok}-val`);
    if (el) el.addEventListener('input', () => {
      EDGE_OPACITY[ok] = parseInt(el.value) / 100;
      if (valEl) valEl.textContent = el.value + '%';
      applyThemeLive();
    });
  }

  // Wire group opacity sliders
  for (const gk of groupKeys) {
    const el = document.getElementById(`lp-gop-${gk}`) as HTMLInputElement;
    const valEl = document.getElementById(`lp-gop-${gk}-val`);
    if (el) el.addEventListener('input', () => {
      EDGE_GROUP_OPACITY[gk] = parseInt(el.value) / 100;
      if (valEl) valEl.textContent = el.value + '%';
      applyThemeLive();
    });
  }

  // Wire tier pickers
  for (const td of tierDefs) {
    const el = document.getElementById(`lp-tier-${td.tier}`) as HTMLInputElement;
    if (el) el.addEventListener('input', () => { TIER_COLORS[td.tier] = el.value; applyThemeLive(); });
  }

  // Wire status dot pickers
  for (const dk of dotKeys) {
    const el = document.getElementById(`lp-dot-${dk}`) as HTMLInputElement;
    if (el) el.addEventListener('input', () => { STATUS_DOT[dk] = el.value; applyThemeLive(); });
  }

  // Save button
  document.getElementById('lp-save')?.addEventListener('click', async () => {
    await saveTheme();
    const st = document.getElementById('lp-status');
    if (st) { st.textContent = 'Saved'; st.style.color = STATUS_DOT.active; setTimeout(() => { st.textContent = ''; }, 2000); }
  });

  // Reset button — clear saved theme, reload defaults
  document.getElementById('lp-reset')?.addEventListener('click', async () => {
    try {
      await fetch('/api/theme', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: '{}' });
    } catch {}
    // Restore defaults
    EDGE_COLORS = { fires: '#f59e0b', calls: '#3b82f6', reads: '#c084fc', writes: '#60a5fa', uses: '#eab308', loads: '#a78bfa', configures: '#6b7280' };
    EDGE_STATUS = { broken: '#ef4444', deprecated: '#6b7280', pulse: '#22D3EE' };
    EDGE_OPACITY = { active: 0.75, idle: 0.35, broken: 0.5, deprecated: 0.15 };
    STATUS_DOT = { active: '#22c55e', idle: '#22D3EE', unhealthy: '#fbbf24', missing: '#ef4444', onDemand: '#a78bfa', phantom: '#6b7280', deprecated: '#4b5563' };
    TIER_COLORS = { 0: '#f97316', 1: '#3b82f6', 2: '#8b5cf6', 3: '#14b8a6', 9: '#6b7280' };
    applyThemeLive();
    buildLegendPanel(panel);
    const st = document.getElementById('lp-status');
    if (st) { st.textContent = 'Reset to defaults'; st.style.color = '#94a3b8'; setTimeout(() => { st.textContent = ''; }, 2000); }
  });
}

// ── Init + Refresh ──────────────────────────────────────────

export async function initGraph() {
  // Load persisted theme before any rendering
  await loadTheme();

  tooltip = document.getElementById('tooltip')!;
  svg = d3.select('#graph-svg');

  // Dark background
  svg.style('background', '#080410');

  zoomBehavior = d3.zoom()
    .scaleExtent([0.15, 3])
    .on('zoom', (event: any) => mainG.attr('transform', event.transform));
  svg.call(zoomBehavior);
  svg.on('dblclick.zoom', null);

  // Click on empty space closes side panel + deselects nodes
  svg.on('click', (event: MouseEvent) => {
    if (event.target === svg.node()) {
      closeSidePanel();
      mainG.selectAll('.shape-main').attr('stroke-width', 2);
    }
  });
  mainG = svg.append('g');
  edgeLayer = null; nodeLayer = null; activeEdgeLayer = null;

  // Load saved positions + detached state + transform
  let savedTransform: { x: number; y: number; k: number } | null = null;
  try {
    const lr = await fetch('/api/layout');
    const ld = await lr.json();
    savedPositions = ld.positions || {};
    detachedNodes.clear();
    if (Array.isArray(ld.detached)) {
      for (const id of ld.detached) detachedNodes.add(id);
    }
    if (ld.transform && typeof ld.transform.k === 'number') {
      savedTransform = ld.transform;
    }
  } catch {}

  // Load + render
  const res = await fetch('/api/graph');
  const data: GraphData = await res.json();
  render(data);

  // Rebuild satellites from saved detached state + current positions
  if (detachedNodes.size > 0 && currentData) {
    const groups = new Set(currentData.nodes.filter(n => detachedNodes.has(n.id)).map(n => n.group));
    for (const g of groups) rebuildSatellites(g, currentData.nodes);
    refreshSubgraphs(mainG, currentData.nodes, currentData.edges,
      new Map(currentData.nodes.map(n => [n.id, n])));
  }

  // Restore saved zoom/pan transform
  if (savedTransform) {
    const t = d3.zoomIdentity.translate(savedTransform.x, savedTransform.y).scale(savedTransform.k);
    svg.call(zoomBehavior.transform, t);
  }

  buildPulseMaps(data.nodes, data.edges);
  startPulseSystem();
}

export async function rescanNodes() {
  try {
    // Snapshot old state for diff
    const oldNodes = new Map<string, { signals: Signals; actual: boolean }>();
    const oldEdgeStatus = new Map<string, string>();
    if (currentData) {
      for (const n of currentData.nodes) oldNodes.set(n.id, { signals: { ...n.signals }, actual: n.actual });
      for (const e of currentData.edges) oldEdgeStatus.set(`${e.sourceId}->${e.targetId}`, e.telemetry?.lastStatus || '');
    }

    // Re-fetch full graph (server re-scans for unexpected nodes)
    const res = await fetch('/api/graph');
    const data: GraphData = await res.json();

    // Reload saved positions (may have been updated)
    try {
      const lr = await fetch('/api/layout');
      const ld = await lr.json();
      savedPositions = ld.positions || {};
      detachedNodes.clear();
      if (Array.isArray(ld.detached)) {
        for (const id of ld.detached) detachedNodes.add(id);
      }
    } catch {}

    // Compute diff
    const diff = computeRescanDiff(oldNodes, oldEdgeStatus, data);

    // Full re-render
    render(data);
    buildPulseMaps(data.nodes, data.edges);

    // Rebuild satellites from detached state
    if (detachedNodes.size > 0 && currentData) {
      const groups = new Set(currentData.nodes.filter(n => detachedNodes.has(n.id)).map(n => n.group));
      for (const g of groups) rebuildSatellites(g, currentData.nodes);
      refreshSubgraphs(mainG, currentData.nodes, currentData.edges,
        new Map(currentData.nodes.map(n => [n.id, n])));
    }

    // Highlight changed nodes + show toast
    if (diff.changedIds.size > 0) {
      for (const id of diff.changedIds) {
        const ng = mainG.select(`.node-${id}`);
        if (ng.empty()) continue;
        const shape = ng.select('.shape-main');
        if (!shape.empty()) {
          const origStroke = shape.attr('stroke');
          const origWidth = shape.attr('stroke-width');
          shape.attr('stroke', '#fff').attr('stroke-width', 4);
          shape.transition().duration(1500).attr('stroke', origStroke).attr('stroke-width', origWidth);
        }
      }
    }
    showRescanToast(diff);
  } catch (err) {
    console.error('Rescan failed:', err);
    showRescanToast(null);
  }
}

interface RescanDiff {
  added: string[];       // node labels that appeared
  removed: string[];     // node labels that disappeared
  recovered: string[];   // nodes that went from missing → exists
  lost: string[];        // nodes that went from exists → missing
  activated: string[];   // nodes that became active
  deactivated: string[]; // nodes that lost active
  edgesRewired: number;  // edges whose status changed
  changedIds: Set<string>; // all node IDs that changed (for highlighting)
  unchanged: boolean;
}

function computeRescanDiff(
  oldNodes: Map<string, { signals: Signals; actual: boolean }>,
  oldEdgeStatus: Map<string, string>,
  newData: GraphData
): RescanDiff {
  const diff: RescanDiff = {
    added: [], removed: [], recovered: [], lost: [],
    activated: [], deactivated: [], edgesRewired: 0,
    changedIds: new Set(), unchanged: true,
  };

  if (oldNodes.size === 0) {
    // First load — nothing to compare
    return diff;
  }

  const newNodeIds = new Set(newData.nodes.map(n => n.id));

  // Nodes that appeared (new unexpected nodes, etc.)
  for (const n of newData.nodes) {
    const old = oldNodes.get(n.id);
    if (!old) {
      diff.added.push(n.label);
      diff.changedIds.add(n.id);
      diff.unchanged = false;
      continue;
    }
    // Status transitions
    if (!old.signals.exists && n.signals.exists) {
      diff.recovered.push(n.label);
      diff.changedIds.add(n.id);
      diff.unchanged = false;
    } else if (old.signals.exists && !n.signals.exists) {
      diff.lost.push(n.label);
      diff.changedIds.add(n.id);
      diff.unchanged = false;
    }
    if (!old.signals.active && n.signals.active) {
      diff.activated.push(n.label);
      diff.changedIds.add(n.id);
      diff.unchanged = false;
    } else if (old.signals.active && !n.signals.active) {
      diff.deactivated.push(n.label);
      diff.changedIds.add(n.id);
      diff.unchanged = false;
    }
  }

  // Nodes that disappeared
  for (const [id, old] of oldNodes) {
    if (!newNodeIds.has(id)) {
      diff.removed.push(id); // we don't have the label anymore
      diff.unchanged = false;
    }
  }

  // Edge status changes
  for (const e of newData.edges) {
    const key = `${e.sourceId}->${e.targetId}`;
    const oldStatus = oldEdgeStatus.get(key);
    const newStatus = e.telemetry?.lastStatus || '';
    if (oldStatus !== undefined && oldStatus !== newStatus) {
      diff.edgesRewired++;
      diff.unchanged = false;
      // Highlight both endpoints
      diff.changedIds.add(e.sourceId);
      diff.changedIds.add(e.targetId);
    }
  }

  return diff;
}

function showRescanToast(diff: RescanDiff | null) {
  // Remove any existing toast
  document.getElementById('rescan-toast')?.remove();

  const toast = document.createElement('div');
  toast.id = 'rescan-toast';
  toast.style.cssText = `
    position: fixed; bottom: 24px; left: 50%; transform: translateX(-50%);
    background: #1a1a2e; border: 1px solid #333; border-radius: 8px;
    padding: 10px 20px; color: #e0e0e0; font-size: 12px; z-index: 9999;
    box-shadow: 0 4px 20px rgba(0,0,0,0.5); max-width: 600px;
    transition: opacity 0.3s; font-family: monospace;
  `;

  if (!diff) {
    toast.innerHTML = `<span style="color:${STATUS_DOT.missing}">Rescan failed</span>`;
  } else if (diff.unchanged) {
    toast.innerHTML = `<span style="color:${TIER_COLOR_DEFAULT}">Rescan: no changes detected</span>`;
  } else {
    const parts: string[] = [];
    if (diff.recovered.length) parts.push(`<span style="color:${STATUS_DOT.active}">+${diff.recovered.length} recovered</span> (${diff.recovered.join(', ')})`);
    if (diff.added.length) parts.push(`<span style="color:${OVERLAY_COLORS.unexpected}">+${diff.added.length} new</span> (${diff.added.join(', ')})`);
    if (diff.lost.length) parts.push(`<span style="color:${STATUS_DOT.missing}">-${diff.lost.length} lost</span> (${diff.lost.join(', ')})`);
    if (diff.removed.length) parts.push(`<span style="color:${STATUS_DOT.missing}">-${diff.removed.length} removed</span>`);
    if (diff.activated.length) parts.push(`<span style="color:${STATUS_DOT.active}">${diff.activated.length} activated</span>`);
    if (diff.deactivated.length) parts.push(`<span style="color:${STATUS_DOT.unhealthy}">${diff.deactivated.length} deactivated</span>`);
    if (diff.edgesRewired) parts.push(`<span style="color:${STATUS_DOT.onDemand}">${diff.edgesRewired} edges rewired</span>`);
    toast.innerHTML = `Rescan: ${parts.join(' · ')}`;
  }

  document.body.appendChild(toast);
  setTimeout(() => { toast.style.opacity = '0'; }, 5000);
  setTimeout(() => { toast.remove(); }, 5400);
}

export async function refreshGraph() {
  try {
    const res = await fetch('/api/graph/pulse');
    const pulse = await res.json();
    if (!currentData) return;

    const pulseMap = new Map(pulse.nodes.map((n: any) => [n.id, n]));
    for (const node of currentData.nodes) {
      const p = pulseMap.get(node.id) as any;
      if (p) { node.signals = p.signals; node.actual = p.actual; if (p.meta) node.meta = { ...node.meta, ...p.meta }; }
    }

    // Update status dots + opacity (skip deprecated nodes — they stay dimmed)
    for (const node of currentData.nodes) {
      const ng = mainG.select(`.node-${node.id}`);
      if (ng.empty()) continue;
      ng.select('.status-dot').transition().duration(300).attr('fill', statusColor(node));
      if (node.deprecated) ng.style('opacity', '0.3');
      else if (!node.signals.exists) ng.style('opacity', '0.35');
      else if (!node.signals.active) ng.style('opacity', '0.65');
      else ng.style('opacity', '1');

      // Update live-data text (row counts, file sizes)
      const liveText = node.meta.rowCount != null && (node.type === 'store_db' || node.type === 'store_json') ? `${node.meta.rowCount} ${node.meta.countLabel || 'rows'}` :
                        node.meta.rowCount != null && node.type === 'worker' ? `${node.meta.rowCount} runs` :
                        node.meta.fileSize ? `${(node.meta.fileSize/1024).toFixed(1)} KB` : '';
      ng.select('.live-data').text(liveText);
    }

    // Refresh summary bar with updated signal counts
    updateSummaryBar(currentData);

    // Signal-based edge pulse: active nodes that have NO JSONL coverage
    // propagate outgoing edges. Covers unexpected nodes, background workers,
    // config nodes — anything the server detects as active but has no JSONL trace.
    // Triggers, scripts, and services are already covered precisely by processLines().
    // V05: Only pulse once per node per active period — clear tracking when node becomes inactive.
    if (outgoingEdges && edgeIndexMap) {
      const COVERED_TYPES = new Set(['trigger', 'script', 'engine', 'service', 'config']);
      for (const node of currentData.nodes) {
        if (!node.signals.active) {
          _signalPulsedNodes.delete(node.id); // reset so it can pulse again if re-activated
          continue;
        }
        if (COVERED_TYPES.has(node.type)) continue; // covered by processLines
        if (_signalPulsedNodes.has(node.id)) continue; // V05: already pulsed this active period
        _signalPulsedNodes.add(node.id);
        const edges = outgoingEdges.get(node.id);
        if (!edges) continue;
        for (const ek of edges) {
          const idx = edgeIndexMap.get(ek);
          if (idx !== undefined) {
            pulseEdge(ek, 0.25);
          }
        }
      }
    }
  } catch {}
}
